{
  "name": "ZenFinance AI",
  "description": "Uma plataforma completa para gestão financeira pessoal com insights inteligentes impulsionados por IA, controle de gastos, metas de economia e consultoria financeira em tempo real.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type TransactionType = 'income' | 'expense';

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  category: string;
  date: string;
  type: TransactionType;
}

export interface Budget {
  category: string;
  limit: number;
  spent: number;
}

export interface FinancialGoal {
  id: string;
  name: string;
  targetAmount: number;
  currentAmount: number;
  deadline: string;
}

export interface FinancialData {
  transactions: Transaction[];
  budgets: Budget[];
  goals: FinancialGoal[];
}

export type AppView = 'dashboard' | 'transactions' | 'budgets' | 'goals' | 'advisor';

import { GoogleGenAI, Type } from "@google/genai";
import { FinancialData } from "../types";

export const getFinancialAdvice = async (data: FinancialData, userQuery: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const summary = {
    totalIncome: data.transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0),
    totalExpense: data.transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0),
    categories: Array.from(new Set(data.transactions.map(t => t.category))),
    goalProgress: data.goals.map(g => `${g.name}: ${(g.currentAmount / g.targetAmount * 100).toFixed(1)}%`)
  };

  const systemInstruction = `
    Você é o ZenFinance AI, um consultor financeiro pessoal de elite. 
    Seu objetivo é ajudar o usuário a organizar sua vida financeira, economizar dinheiro e investir melhor.
    Analise os dados fornecidos e responda de forma clara, motivadora e baseada em dados.
    Contexto do Usuário:
    - Renda Total: R$ ${summary.totalIncome}
    - Despesas Totais: R$ ${summary.totalExpense}
    - Saldo Atual: R$ ${summary.totalIncome - summary.totalExpense}
    - Metas: ${summary.goalProgress.join(', ')}

    Regras:
    1. Se o usuário estiver gastando mais do que ganha, seja firme mas construtivo.
    2. Sugira cortes em categorias específicas se notar gastos altos.
    3. Use Markdown para formatar tabelas ou listas.
    4. Responda em Português do Brasil.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userQuery,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.7,
      },
    });

    return response.text;
  } catch (error) {
    console.error("Erro ao obter conselhos:", error);
    return "Desculpe, tive um problema ao analisar seus dados. Tente novamente em instantes.";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  Target, 
  Wallet, 
  BrainCircuit, 
  Plus, 
  TrendingUp, 
  TrendingDown,
  Menu,
  X,
  Bell
} from 'lucide-react';
import { AppView, Transaction, Budget, FinancialGoal } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import AIAdvisor from './components/AIAdvisor';

const INITIAL_TRANSACTIONS: Transaction[] = [
  { id: '1', description: 'Salário Mensal', amount: 5000, category: 'Salário', date: '2023-11-01', type: 'income' },
  { id: '2', description: 'Aluguel', amount: 1500, category: 'Moradia', date: '2023-11-05', type: 'expense' },
  { id: '3', description: 'Supermercado', amount: 600, category: 'Alimentação', date: '2023-11-10', type: 'expense' },
  { id: '4', description: 'Freelance Design', amount: 1200, category: 'Extra', date: '2023-11-12', type: 'income' },
  { id: '5', description: 'Restaurante', amount: 150, category: 'Lazer', date: '2023-11-15', type: 'expense' },
];

const INITIAL_BUDGETS: Budget[] = [
  { category: 'Moradia', limit: 1600, spent: 1500 },
  { category: 'Alimentação', limit: 800, spent: 600 },
  { category: 'Lazer', limit: 400, spent: 150 },
  { category: 'Transporte', limit: 300, spent: 0 },
];

const INITIAL_GOALS: FinancialGoal[] = [
  { id: '1', name: 'Reserva de Emergência', targetAmount: 15000, currentAmount: 3000, deadline: '2024-12-31' },
  { id: '2', name: 'Viagem Japão', targetAmount: 20000, currentAmount: 5000, deadline: '2025-06-30' },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [budgets, setBudgets] = useState<Budget[]>(() => {
    const saved = localStorage.getItem('zen_budgets');
    return saved ? JSON.parse(saved) : INITIAL_BUDGETS;
  });
  const [goals, setGoals] = useState<FinancialGoal[]>(() => {
    const saved = localStorage.getItem('zen_goals');
    return saved ? JSON.parse(saved) : INITIAL_GOALS;
  });

  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [transactions, budgets, goals]);

  const financialData = useMemo(() => ({
    transactions,
    budgets,
    goals
  }), [transactions, budgets, goals]);

  const addTransaction = (t: Transaction) => setTransactions([t, ...transactions]);
  const addGoal = (g: FinancialGoal) => setGoals([...goals, g]);
  const updateBudget = (b: Budget) => setBudgets(budgets.map(item => item.category === b.category ? b : item));

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'Transações', icon: Receipt },
    { id: 'budgets', label: 'Orçamentos', icon: Wallet },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-slate-50">
      {/* Mobile Backdrop */}
      {!isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/20 z-20 md:hidden"
          onClick={() => setIsSidebarOpen(true)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed md:sticky top-0 h-screen z-30 transition-all duration-300
        ${isSidebarOpen ? 'w-64 translate-x-0' : 'w-0 -translate-x-full md:w-20 md:translate-x-0'}
        bg-indigo-900 text-white flex flex-col overflow-hidden
      `}>
        <div className="p-6 flex items-center gap-3">
          <div className="bg-white/10 p-2 rounded-xl">
            <BrainCircuit className="w-6 h-6 text-indigo-300" />
          </div>
          {isSidebarOpen && <span className="text-xl font-bold tracking-tight">ZenFinance</span>}
        </div>

        <nav className="flex-1 px-3 mt-4 space-y-1">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setView(item.id as AppView)}
              className={`
                w-full flex items-center gap-3 px-3 py-3 rounded-lg transition-colors
                ${view === item.id ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800/50'}
              `}
            >
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {isSidebarOpen && <span className="font-medium">{item.label}</span>}
            </button>
          ))}
        </nav>

        <div className="p-4 mt-auto border-t border-indigo-800">
          <button 
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
            className="w-full flex items-center justify-center p-2 rounded hover:bg-indigo-800"
          >
            {isSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        {/* Header */}
        <header className="h-16 glass sticky top-0 z-10 border-b border-slate-200 px-6 flex items-center justify-between">
          <h1 className="text-xl font-semibold text-slate-800 capitalize">
            {navItems.find(i => i.id === view)?.label}
          </h1>
          <div className="flex items-center gap-4">
            <button className="p-2 text-slate-500 hover:text-indigo-600 relative">
              <Bell className="w-5 h-5" />
              <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full"></span>
            </button>
            <div className="flex items-center gap-3 pl-4 border-l border-slate-200">
              <img src="https://picsum.photos/seed/finance/32/32" className="w-8 h-8 rounded-full border border-slate-300" alt="avatar" />
              <div className="hidden sm:block">
                <p className="text-sm font-medium text-slate-700">Usuário Zen</p>
                <p className="text-xs text-slate-500">Premium Plan</p>
              </div>
            </div>
          </div>
        </header>

        {/* View Content */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && <Transactions transactions={transactions} onAdd={addTransaction} />}
          {view === 'budgets' && <Budgets budgets={budgets} onUpdate={updateBudget} />}
          {view === 'goals' && <Goals goals={goals} onAdd={addGoal} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

import React from 'react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend, BarChart, Bar
} from 'recharts';
import { TrendingUp, TrendingDown, DollarSign, Wallet } from 'lucide-react';
import { FinancialData } from '../types';

interface DashboardProps {
  data: FinancialData;
}

export default function Dashboard({ data }: DashboardProps) {
  const { transactions, goals } = data;

  const totalIncome = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
  const totalExpense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
  const balance = totalIncome - totalExpense;

  const chartData = transactions.slice(-10).reverse().map(t => ({
    name: new Date(t.date).toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' }),
    amount: t.type === 'income' ? t.amount : -t.amount,
  }));

  const categoryTotals = transactions
    .filter(t => t.type === 'expense')
    .reduce((acc: any, t) => {
      acc[t.category] = (acc[t.category] || 0) + t.amount;
      return acc;
    }, {});

  const pieData = Object.keys(categoryTotals).map(cat => ({
    name: cat,
    value: categoryTotals[cat]
  }));

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316', '#eab308'];

  return (
    <div className="space-y-6">
      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex items-center gap-4 mb-4">
            <div className="bg-indigo-100 p-3 rounded-xl">
              <Wallet className="w-6 h-6 text-indigo-600" />
            </div>
            <span className="text-slate-500 font-medium">Saldo Total</span>
          </div>
          <p className={`text-3xl font-bold ${balance >= 0 ? 'text-slate-900' : 'text-red-600'}`}>
            R$ {balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </p>
          <div className="mt-4 flex items-center gap-2 text-xs text-slate-500">
            <span className="text-emerald-500 font-semibold">+2.5%</span> em relação ao mês anterior
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex items-center gap-4 mb-4">
            <div className="bg-emerald-100 p-3 rounded-xl">
              <TrendingUp className="w-6 h-6 text-emerald-600" />
            </div>
            <span className="text-slate-500 font-medium">Receitas</span>
          </div>
          <p className="text-3xl font-bold text-slate-900">
            R$ {totalIncome.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </p>
          <div className="mt-4 flex items-center gap-2 text-xs text-slate-500">
            Últimos 30 dias
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex items-center gap-4 mb-4">
            <div className="bg-red-100 p-3 rounded-xl">
              <TrendingDown className="w-6 h-6 text-red-600" />
            </div>
            <span className="text-slate-500 font-medium">Despesas</span>
          </div>
          <p className="text-3xl font-bold text-slate-900">
            R$ {totalExpense.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </p>
          <div className="mt-4 flex items-center gap-2 text-xs text-slate-500">
            Últimos 30 dias
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold mb-6">Fluxo de Caixa (Recentes)</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorAmt" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#6366f1" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip 
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                />
                <Area type="monotone" dataKey="amount" stroke="#6366f1" strokeWidth={2} fillOpacity={1} fill="url(#colorAmt)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold mb-6">Gastos por Categoria</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                   contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                />
                <Legend layout="vertical" align="right" verticalAlign="middle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Goals Summary */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
        <h3 className="text-lg font-semibold mb-4">Resumo de Metas</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {goals.map(goal => {
            const progress = (goal.currentAmount / goal.targetAmount) * 100;
            return (
              <div key={goal.id} className="p-4 border border-slate-100 rounded-xl bg-slate-50">
                <div className="flex justify-between items-center mb-2">
                  <span className="font-medium text-slate-700">{goal.name}</span>
                  <span className="text-xs font-semibold text-indigo-600">{progress.toFixed(0)}%</span>
                </div>
                <div className="w-full bg-slate-200 h-2 rounded-full overflow-hidden">
                  <div 
                    className="bg-indigo-600 h-full transition-all duration-500" 
                    style={{ width: `${progress}%` }}
                  />
                </div>
                <div className="flex justify-between mt-2 text-xs text-slate-500">
                  <span>R$ {goal.currentAmount.toLocaleString()}</span>
                  <span>R$ {goal.targetAmount.toLocaleString()}</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { Search, Plus, Trash2, ArrowUpCircle, ArrowDownCircle, Filter } from 'lucide-react';
import { Transaction, TransactionType } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  onAdd: (t: Transaction) => void;
}

export default function Transactions({ transactions, onAdd }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [showAddModal, setShowAddModal] = useState(false);

  const filteredTransactions = transactions.filter(t => {
    const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          t.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = typeFilter === 'all' || t.type === typeFilter;
    return matchesSearch && matchesType;
  });

  const [newTx, setNewTx] = useState<Partial<Transaction>>({
    description: '',
    amount: 0,
    category: 'Alimentação',
    type: 'expense',
    date: new Date().toISOString().split('T')[0]
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTx.description || !newTx.amount) return;
    onAdd({
      ...newTx as Transaction,
      id: Math.random().toString(36).substr(2, 9)
    });
    setNewTx({
      description: '',
      amount: 0,
      category: 'Alimentação',
      type: 'expense',
      date: new Date().toISOString().split('T')[0]
    });
    setShowAddModal(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="relative w-full md:w-96">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input 
            type="text" 
            placeholder="Buscar por descrição ou categoria..."
            className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex gap-2 w-full md:w-auto">
          <div className="flex border border-slate-200 rounded-xl bg-white overflow-hidden">
            <button 
              onClick={() => setTypeFilter('all')}
              className={`px-4 py-2 text-sm font-medium ${typeFilter === 'all' ? 'bg-slate-100 text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Todos
            </button>
            <button 
              onClick={() => setTypeFilter('income')}
              className={`px-4 py-2 text-sm font-medium ${typeFilter === 'income' ? 'bg-emerald-50 text-emerald-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Receitas
            </button>
            <button 
              onClick={() => setTypeFilter('expense')}
              className={`px-4 py-2 text-sm font-medium ${typeFilter === 'expense' ? 'bg-red-50 text-red-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Despesas
            </button>
          </div>
          <button 
            onClick={() => setShowAddModal(true)}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 font-medium transition-colors"
          >
            <Plus className="w-5 h-5" />
            Nova Transação
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-6 py-4 text-sm font-semibold text-slate-600">Descrição</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600">Categoria</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600">Data</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 text-right">Valor</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredTransactions.map(t => (
              <tr key={t.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4">
                  <div className="flex items-center gap-3">
                    {t.type === 'income' ? (
                      <ArrowUpCircle className="w-5 h-5 text-emerald-500" />
                    ) : (
                      <ArrowDownCircle className="w-5 h-5 text-red-400" />
                    )}
                    <span className="font-medium text-slate-800">{t.description}</span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className="px-3 py-1 bg-slate-100 text-slate-600 text-xs font-semibold rounded-full uppercase tracking-wider">
                    {t.category}
                  </span>
                </td>
                <td className="px-6 py-4 text-slate-500 text-sm">
                  {new Date(t.date).toLocaleDateString('pt-BR')}
                </td>
                <td className={`px-6 py-4 text-right font-bold ${t.type === 'income' ? 'text-emerald-600' : 'text-slate-700'}`}>
                  {t.type === 'income' ? '+' : '-'} R$ {t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {filteredTransactions.length === 0 && (
          <div className="p-12 text-center text-slate-400">
            Nenhuma transação encontrada.
          </div>
        )}
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50">
          <div className="bg-white rounded-2xl w-full max-w-md p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold">Adicionar Transação</h3>
              <button onClick={() => setShowAddModal(false)}><X className="w-6 h-6 text-slate-400" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Descrição</label>
                <input 
                  type="text" required
                  className="w-full px-4 py-2 border rounded-xl"
                  value={newTx.description}
                  onChange={e => setNewTx({...newTx, description: e.target.value})}
                />
              </div>
