                <span className="text-slate-500">Gasto: R$ {budget.spent.toLocaleString()}</span>
                <span className="text-slate-700 font-semibold">Limite: R$ {budget.limit.toLocaleString()}</span>
              </div>

              <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden mb-4">
                <div 
                  className={`h-full transition-all duration-700 ${isOver ? 'bg-red-500' : isNear ? 'bg-amber-500' : 'bg-indigo-500'}`}
                  style={{ width: `${Math.min(percentage, 100)}%` }}
                />
              </div>

              <div className="mt-auto pt-4 flex justify-between items-center border-t border-slate-50">
                <span className={`text-xs font-bold px-2 py-1 rounded-full ${isOver ? 'bg-red-100 text-red-600' : isNear ? 'bg-amber-100 text-amber-600' : 'bg-emerald-100 text-emerald-600'}`}>
                  {isOver ? 'Limite Excedido' : `${(100 - percentage).toFixed(0)}% restante`}
                </span>
                <button 
                  onClick={() => onUpdate({...budget, limit: budget.limit + 100})}
                  className="text-indigo-600 text-xs font-bold hover:underline"
                >
                  Ajustar Limite
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

