import React, { useState, useRef, useEffect } from 'react';
import { BrainCircuit, Send, Loader2, Sparkles, MessageSquare } from 'lucide-react';
import { FinancialData } from '../types';
import { getFinancialAdvice } from '../services/gemini';

interface Message {
  id: string;
  role: 'user' | 'ai';
  content: string;
}

export default function AIAdvisor({ data }: { data: FinancialData }) {
  const [messages, setMessages] = useState<Message[]>([
    { id: '1', role: 'ai', content: 'Olá! Sou seu assistente ZenFinance. Analisei seus dados financeiros. Em que posso te ajudar hoje? Você pode perguntar sobre seus gastos, dicas para economizar ou como atingir suas metas mais rápido.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage: Message = { id: Date.now().toString(), role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const advice = await getFinancialAdvice(data, input);
    const aiMessage: Message = { id: (Date.now() + 1).toString(), role: 'ai', content: advice || 'Desculpe, tive um erro.' };

    setMessages(prev => [...prev, aiMessage]);
    setIsLoading(false);
  };

  return (
    <div className="h-[calc(100vh-12rem)] flex flex-col bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      {/* Advisor Header */}
      <div className="bg-indigo-600 p-6 text-white flex items-center gap-4">
        <div className="bg-white/20 p-3 rounded-2xl backdrop-blur-md">
          <BrainCircuit className="w-8 h-8 text-white" />
        </div>
        <div>
          <h2 className="text-xl font-bold">ZenAdvisor AI</h2>
          <p className="text-indigo-100 text-sm flex items-center gap-2">
            <span className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></span>
            Online & Analisando seus dados
          </p>
        </div>
      </div>

      {/* Chat Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50"
      >
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`
              max-w-[85%] rounded-3xl p-4 shadow-sm
              ${msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white text-slate-800 border border-slate-100 rounded-tl-none'}
            `}>
              {msg.role === 'ai' && (
                <div className="flex items-center gap-2 mb-2 text-indigo-600 text-xs font-bold uppercase tracking-widest">
                  <Sparkles className="w-3 h-3" /> Inteligência Zen
                </div>
              )}
              <div className="prose prose-sm max-w-none prose-slate whitespace-pre-wrap">
                {msg.content}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-3">
              <Loader2 className="w-5 h-5 text-indigo-600 animate-spin" />
              <span className="text-sm text-slate-500 font-medium">Zen está pensando...</span>
            </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-100">
        <form onSubmit={handleSend} className="relative">
          <input 
            type="text"
            placeholder="Pergunte algo sobre suas finanças..."
            className="w-full pl-6 pr-16 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all"
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button 
            type="submit"
            disabled={!input.trim() || isLoading}
            className={`
              absolute right-2 top-1/2 -translate-y-1/2 p-3 rounded-xl transition-all
              ${input.trim() && !isLoading ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-400'}
            `}
          >
            <Send className="w-5 h-5" />
          </button>
        </form>
        <div className="mt-3 flex justify-center gap-4">
          {['Como reduzir despesas?', 'Dica de investimento', 'Resumo da semana'].map((hint) => (
            <button 
              key={hint}
              onClick={() => setInput(hint)}
              className="text-xs font-medium text-slate-500 hover:text-indigo-600 transition-colors px-3 py-1 bg-slate-100 rounded-full border border-slate-200"
            >
              {hint}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

