import React, { useState } from 'react';
import { Jar } from '../types';
import { Plus, Trash2, Edit2, Archive, AlertCircle, Save } from 'lucide-react';

interface PotesProps {
  potes: Jar[];
  onUpdate: (potes: Jar[]) => void;
}

export default function Potes({ potes, onUpdate }: PotesProps) {
  const [showAdd, setShowAdd] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newPote, setNewPote] = useState({ name: '', percentage: 0 });

  const totalPercentage = potes.reduce((acc, p) => acc + p.percentage, 0);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (totalPercentage + newPote.percentage > 100) {
      alert("A soma dos percentuais não pode ultrapassar 100%!");
      return;
    }
    const pote: Jar = {
      id: Math.random().toString(36).substr(2, 9),
      name: newPote.name,
      percentage: newPote.percentage,
      balance: 0
    };
    onUpdate([...potes, pote]);
    setNewPote({ name: '', percentage: 0 });
    setShowAdd(false);
  };

  const handleDelete = (id: string) => {
    if (confirm("Deseja excluir este pote? O saldo será perdido no sistema de potes (mas as transações globais permanecem).")) {
      onUpdate(potes.filter(p => p.id !== id));
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl border border-slate-100 flex items-center justify-between shadow-sm">
        <div>
          <h2 className="text-lg font-bold text-slate-800">Sua Estratégia</h2>
          <p className="text-slate-500 text-sm">Distribuição total: <span className={`font-bold ${totalPercentage > 100 ? 'text-red-500' : 'text-indigo-600'}`}>{totalPercentage}%</span> / 100%</p>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-2 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all"
        >
          <Plus className="w-5 h-5" /> Criar Pote
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {potes.map((pote) => (
          <div key={pote.id} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 group">
            <div className="flex justify-between items-start mb-4">
              <div className="bg-indigo-50 p-3 rounded-2xl">
                <Archive className="w-6 h-6 text-indigo-600" />
              </div>
              <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => handleDelete(pote.id)} className="p-2 text-slate-400 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
              </div>
            </div>

            <h3 className="text-xl font-bold text-slate-800 mb-1">{pote.name}</h3>
            <div className="flex items-center gap-2 mb-4">
              <span className="px-2 py-1 bg-indigo-100 text-indigo-700 text-xs font-bold rounded-lg">{pote.percentage}% do aporte</span>
            </div>

            <div className="bg-slate-50 p-4 rounded-2xl mb-4">
              <p className="text-xs text-slate-500 uppercase font-bold tracking-wider mb-1">Saldo no Pote</p>
              <p className="text-2xl font-black text-slate-900">R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            </div>

            <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
              <div className="bg-indigo-600 h-full" style={{ width: `${pote.percentage}%` }} />
            </div>
          </div>
        ))}
      </div>

      {showAdd && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50">
          <div className="bg-white rounded-3xl w-full max-w-md p-8 shadow-2xl">
            <h3 className="text-2xl font-bold mb-6">Novo Pote de Reserva</h3>
            <form onSubmit={handleAdd} className="space-y-4">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Nome do Pote</label>
                <input 
                  type="text" required placeholder="ex: Carro, Emergência, Festa..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500"
                  value={newPote.name} onChange={e => setNewPote({...newPote, name: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Porcentagem de Receita (%)</label>
                <input 
                  type="number" required min="1" max="100"
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500"
                  value={newPote.percentage || ''} onChange={e => setNewPote({...newPote, percentage: parseInt(e.target.value)})}
                />
                <p className="text-[10px] text-slate-400 mt-2 italic">* Sempre que entrar dinheiro, {newPote.percentage || 0}% irá para este pote.</p>
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowAdd(false)} className="flex-1 py-3 text-slate-500 font-bold">Cancelar</button>
                <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700">Criar Pote</button>
              </div>
            </form>
          </div>
        </div>
      )}
