  );
}

import React, { useState } from 'react';
import { Jar } from '../types';
import { Plus, Trash2, Edit2, Archive, AlertCircle, Save, X } from 'lucide-react';

interface PotesProps {
  potes: Jar[];
  onUpdate: (potes: Jar[]) => void;
}

export default function Potes({ potes, onUpdate }: PotesProps) {
  const [showModal, setShowModal] = useState<'add' | 'edit' | null>(null);
  const [currentPote, setCurrentPote] = useState<Partial<Jar>>({ name: '', percentage: 0 });

  const totalPercentage = potes.reduce((acc, p) => acc + p.percentage, 0);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const otherPotes = showModal === 'edit' ? potes.filter(p => p.id !== currentPote.id) : potes;
    const currentTotal = otherPotes.reduce((acc, p) => acc + p.percentage, 0);

    if (currentTotal + (currentPote.percentage || 0) > 100) {
      alert("A soma dos percentuais não pode ultrapassar 100%!");
      return;
    }

    if (showModal === 'add') {
      const pote: Jar = {
        id: Math.random().toString(36).substr(2, 9),
        name: currentPote.name || 'Novo Pote',
        percentage: currentPote.percentage || 0,
        balance: 0
      };
      onUpdate([...potes, pote]);
    } else if (showModal === 'edit') {
      onUpdate(potes.map(p => p.id === currentPote.id ? { ...p, ...currentPote } as Jar : p));
    }

    setCurrentPote({ name: '', percentage: 0 });
    setShowModal(null);
  };

  const handleEditClick = (pote: Jar) => {
    setCurrentPote(pote);
    setShowModal('edit');
  };

  const handleDelete = (id: string) => {
    if (confirm("Deseja excluir este pote? O saldo será removido do controle de potes.")) {
      onUpdate(potes.filter(p => p.id !== id));
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl border border-slate-100 flex items-center justify-between shadow-sm">
        <div>
          <h2 className="text-lg font-bold text-slate-800">Estratégia de Divisão</h2>
          <p className="text-slate-500 text-sm">Distribuição configurada: <span className={`font-bold ${totalPercentage > 100 ? 'text-red-500' : 'text-indigo-600'}`}>{totalPercentage}%</span> / 100%</p>
        </div>
        <button 
          onClick={() => { setCurrentPote({ name: '', percentage: 0 }); setShowModal('add'); }}
          className="flex items-center gap-2 px-6 py-2 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
        >
          <Plus className="w-5 h-5" /> Criar Pote
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {potes.map((pote) => (
          <div key={pote.id} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 group relative">
            <div className="flex justify-between items-start mb-6">
              <div className="bg-indigo-50 p-3 rounded-2xl">
                <Archive className="w-6 h-6 text-indigo-600" />
              </div>
              <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => handleEditClick(pote)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg"><Edit2 className="w-4 h-4" /></button>
                <button onClick={() => handleDelete(pote.id)} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
              </div>
            </div>

            <h3 className="text-lg font-bold text-slate-700 mb-1">{pote.name}</h3>
            <span className="inline-block px-2 py-1 bg-indigo-100 text-indigo-700 text-[10px] font-black rounded-md uppercase tracking-wider mb-4">
              Aporte de {pote.percentage}%
            </span>

            <div className="mb-6">
              <p className="text-xs text-slate-400 uppercase font-bold tracking-widest mb-1">Saldo Atual</p>
              <p className={`text-3xl font-bold tracking-tight ${pote.balance >= 0 ? 'text-slate-900' : 'text-red-600'}`}>
                R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </p>
            </div>

            <div className="space-y-2">
              <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                <div 
                  className="bg-indigo-600 h-full transition-all duration-500" 
                  style={{ width: `${pote.percentage}%` }} 
                />
              </div>
              <p className="text-[10px] text-slate-400 text-right font-medium">Peso na carteira</p>
            </div>
          </div>
        ))}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-3xl w-full max-w-md p-8 shadow-2xl animate-in fade-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-bold text-slate-800">{showModal === 'add' ? 'Novo Pote' : 'Editar Pote'}</h3>
              <button onClick={() => setShowModal(null)}><X className="w-6 h-6 text-slate-400" /></button>
            </div>
            <form onSubmit={handleSave} className="space-y-5">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Nome do Pote</label>
                <input 
                  type="text" required placeholder="ex: Reserva, Carro, Lazer..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                  value={currentPote.name} onChange={e => setCurrentPote({...currentPote, name: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Porcentagem Automática (%)</label>
                <div className="relative">
                  <input 
                    type="number" required min="1" max="100"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                    value={currentPote.percentage || ''} onChange={e => setCurrentPote({...currentPote, percentage: parseInt(e.target.value)})}
                  />
                  <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">%</span>
                </div>
                <p className="text-[10px] text-slate-400 mt-2 italic">* Define quanto de cada receita este pote absorve.</p>
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowModal(null)} className="flex-1 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-2xl transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all flex items-center justify-center gap-2">
                  <Save className="w-4 h-4" /> {showModal === 'add' ? 'Criar' : 'Salvar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  Target, 
  Wallet, 
  BrainCircuit, 
  Plus, 
  Menu,
  X,
  Bell,
  Archive
} from 'lucide-react';
import { AppView, Transaction, Budget, FinancialGoal, Jar } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';

const INITIAL_TRANSACTIONS: Transaction[] = [
  { id: '1', description: 'Salário Mensal', amount: 5000, category: 'Salário', date: '2023-11-01', type: 'income' },
  { id: '2', description: 'Aluguel', amount: 1500, category: 'Moradia', date: '2023-11-05', type: 'expense', poteId: '1' },
];

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Necessidades Básicas', percentage: 50, balance: 2500 },
  { id: '2', name: 'Investimentos', percentage: 30, balance: 1500 },
  { id: '3', name: 'Lazer', percentage: 20, balance: 1000 },
];

const INITIAL_BUDGETS: Budget[] = [
  { category: 'Moradia', limit: 1600, spent: 1500 },
  { category: 'Alimentação', limit: 800, spent: 0 },
];

const INITIAL_GOALS: FinancialGoal[] = [
  { id: '1', name: 'Reserva de Emergência', targetAmount: 15000, currentAmount: 3000, deadline: '2024-12-31' },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [budgets, setBudgets] = useState<Budget[]>(() => {
    const saved = localStorage.getItem('zen_budgets');
    return saved ? JSON.parse(saved) : INITIAL_BUDGETS;
  });

  const [goals, setGoals] = useState<FinancialGoal[]>(() => {
    const saved = localStorage.getItem('zen_goals');
    return saved ? JSON.parse(saved) : INITIAL_GOALS;
  });

  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [transactions, potes, budgets, goals]);

  const financialData = useMemo(() => ({
    transactions,
    budgets,
    goals,
    potes
  }), [transactions, budgets, goals, potes]);

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);

    const updatedPotes = potes.map(pote => {
      if (t.type === 'income') {
        const share = t.amount * (pote.percentage / 100);
        return { ...pote, balance: pote.balance + share };
      } else {
        if (t.poteId === pote.id) {
          return { ...pote, balance: pote.balance - t.amount };
        }
      }
      return pote;
    });

    setPotes(updatedPotes);
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'potes', label: 'Potes', icon: Archive },
    { id: 'transactions', label: 'Transações', icon: Receipt },
    { id: 'budgets', label: 'Orçamentos', icon: Wallet },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-slate-50">
      {!isSidebarOpen && (
        <div className="fixed inset-0 bg-black/20 z-20 md:hidden" onClick={() => setIsSidebarOpen(true)} />
      )}

      <aside className={`
        fixed md:sticky top-0 h-screen z-30 transition-all duration-300
        ${isSidebarOpen ? 'w-56 translate-x-0' : 'w-0 -translate-x-full md:w-16 md:translate-x-0'}
        bg-indigo-900 text-white flex flex-col overflow-hidden
      `}>
        <div className="p-5 flex items-center gap-2">
          <div className="bg-white/10 p-1.5 rounded-lg">
            <BrainCircuit className="w-5 h-5 text-indigo-300" />
          </div>
          {isSidebarOpen && <span className="text-lg font-bold tracking-tight">ZenFinance</span>}
        </div>

        <nav className="flex-1 px-2 mt-4 space-y-0.5">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setView(item.id as AppView)}
              className={`
                w-full flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors
                ${view === item.id ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800/50'}
              `}
            >
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {isSidebarOpen && <span className="font-medium text-sm">{item.label}</span>}
            </button>
          ))}
        </nav>

        <div className="p-3 mt-auto border-t border-indigo-800">
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-full flex items-center justify-center p-1.5 rounded hover:bg-indigo-800">
            {isSidebarOpen ? <X className="w-4 h-4" /> : <Menu className="w-4 h-4" />}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        <header className="h-14 glass sticky top-0 z-10 border-b border-slate-200 px-5 flex items-center justify-between">
          <h1 className="text-lg font-semibold text-slate-800 capitalize">
            {navItems.find(i => i.id === view)?.label}
          </h1>
          <div className="flex items-center gap-4">
             <div className="flex items-center gap-3 pl-4">
              <img src="https://picsum.photos/seed/finance/32/32" className="w-7 h-7 rounded-full border border-slate-300" alt="avatar" />
              <div className="hidden sm:block">
                <p className="text-xs font-medium text-slate-700">Usuário Zen</p>
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && <Transactions transactions={transactions} potes={potes} onAdd={handleAddTransaction} />}
          {view === 'budgets' && <Budgets budgets={budgets} onUpdate={(b) => setBudgets(budgets.map(item => item.category === b.category ? b : item))} />}
          {view === 'goals' && <Goals goals={goals} onAdd={(g) => setGoals([...goals, g])} />}
          {view === 'potes' && <Potes potes={potes} onUpdate={setPotes} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Jar } from '../types';
import { Plus, Trash2, Edit2, Archive, X, Save } from 'lucide-react';

interface PotesProps {
  potes: Jar[];
  onUpdate: (potes: Jar[]) => void;
}

export default function Potes({ potes, onUpdate }: PotesProps) {
  const [showModal, setShowModal] = useState<'add' | 'edit' | null>(null);
  const [currentPote, setCurrentPote] = useState<Partial<Jar>>({ name: '', percentage: 0 });

  const totalPercentage = potes.reduce((acc, p) => acc + p.percentage, 0);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const otherPotes = showModal === 'edit' ? potes.filter(p => p.id !== currentPote.id) : potes;
    const currentTotal = otherPotes.reduce((acc, p) => acc + p.percentage, 0);

    if (currentTotal + (currentPote.percentage || 0) > 100) {
      alert("A soma dos percentuais não pode ultrapassar 100%!");
      return;
    }

    if (showModal === 'add') {
      const pote: Jar = {
        id: Math.random().toString(36).substr(2, 9),
        name: currentPote.name || 'Novo Pote',
        percentage: currentPote.percentage || 0,
        balance: 0
      };
      onUpdate([...potes, pote]);
    } else if (showModal === 'edit') {
      onUpdate(potes.map(p => p.id === currentPote.id ? { ...p, ...currentPote } as Jar : p));
    }

    setCurrentPote({ name: '', percentage: 0 });
    setShowModal(null);
  };

  const handleEditClick = (pote: Jar) => {
    setCurrentPote(pote);
    setShowModal('edit');
  };

  const handleDelete = (id: string) => {
    if (confirm("Deseja excluir este pote? O saldo será removido do controle de potes.")) {
      onUpdate(potes.filter(p => p.id !== id));
    }
  };

  return (
    <div className="space-y-5">
      <div className="bg-white p-5 rounded-2xl border border-slate-100 flex items-center justify-between shadow-sm">
        <div>
          <h2 className="text-base font-bold text-slate-800">Estratégia de Divisão</h2>
          <p className="text-slate-500 text-xs">Distribuição: <span className={`font-bold ${totalPercentage > 100 ? 'text-red-500' : 'text-indigo-600'}`}>{totalPercentage}%</span> / 100%</p>
        </div>
        <button 
          onClick={() => { setCurrentPote({ name: '', percentage: 0 }); setShowModal('add'); }}
          className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all text-sm"
        >
          <Plus className="w-4 h-4" /> Criar Pote
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
        {potes.map((pote) => (
          <div key={pote.id} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 group relative">
            <div className="flex justify-between items-start mb-4">
              <div className="bg-indigo-50 p-2 rounded-xl">
                <Archive className="w-5 h-5 text-indigo-600" />
              </div>
              <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => handleEditClick(pote)} className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg"><Edit2 className="w-3.5 h-3.5" /></button>
                <button onClick={() => handleDelete(pote.id)} className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg"><Trash2 className="w-3.5 h-3.5" /></button>
              </div>
            </div>

            <h3 className="text-base font-bold text-slate-700 mb-0.5">{pote.name}</h3>
            <span className="inline-block px-1.5 py-0.5 bg-indigo-100 text-indigo-700 text-[9px] font-black rounded uppercase tracking-wider mb-3">
              Aporte de {pote.percentage}%
            </span>

            <div className="mb-4">
              <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest mb-0.5">Saldo Atual</p>
              <p className={`text-2xl font-bold tracking-tight ${pote.balance >= 0 ? 'text-slate-900' : 'text-red-600'}`}>
                R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </p>
            </div>

            <div className="space-y-1.5">
              <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                <div 
                  className="bg-indigo-600 h-full transition-all duration-500" 
                  style={{ width: `${pote.percentage}%` }} 
                />
              </div>
            </div>
          </div>
        ))}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-sm p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-5">
              <h3 className="text-xl font-bold text-slate-800">{showModal === 'add' ? 'Novo Pote' : 'Editar Pote'}</h3>
              <button onClick={() => setShowModal(null)}><X className="w-5 h-5 text-slate-400" /></button>
            </div>
            <form onSubmit={handleSave} className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-700 mb-1.5">Nome do Pote</label>
                <input 
                  type="text" required placeholder="ex: Reserva, Carro..."
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:bg-white text-sm outline-none transition-all"
                  value={currentPote.name} onChange={e => setCurrentPote({...currentPote, name: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-700 mb-1.5">Porcentagem Automática (%)</label>
                <div className="relative">
                  <input 
                    type="number" required min="1" max="100"
                    className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:bg-white text-sm outline-none transition-all"
                    value={currentPote.percentage || ''} onChange={e => setCurrentPote({...currentPote, percentage: parseInt(e.target.value)})}
                  />
                  <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-xs">%</span>
                </div>
              </div>
              <div className="flex gap-2 pt-3">
                <button type="button" onClick={() => setShowModal(null)} className="flex-1 py-2.5 text-slate-500 font-bold text-sm hover:bg-slate-50 rounded-xl transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-2.5 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 text-sm flex items-center justify-center gap-2">
                  <Save className="w-4 h-4" /> {showModal === 'add' ? 'Criar' : 'Salvar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { Search, Plus, ArrowUpCircle, ArrowDownCircle, X } from 'lucide-react';
import { Transaction, TransactionType, Jar } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  onAdd: (t: Transaction) => void;
}

export default function Transactions({ transactions, potes, onAdd }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [showAddModal, setShowAddModal] = useState(false);

  const filteredTransactions = transactions.filter(t => {
    const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          t.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = typeFilter === 'all' || t.type === typeFilter;
    return matchesSearch && matchesType;
  });

  const [newTx, setNewTx] = useState<Partial<Transaction>>({
    description: '',
    amount: 0,
    category: 'Alimentação',
    type: 'expense',
    date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTx.description || !newTx.amount) return;
    onAdd({
      ...newTx as Transaction,
      id: Math.random().toString(36).substr(2, 9)
    });
    setNewTx({
      description: '',
      amount: 0,
      category: 'Alimentação',
      type: 'expense',
      date: new Date().toISOString().split('T')[0],
      poteId: potes.length > 0 ? potes[0].id : ''
    });
    setShowAddModal(false);
  };

  return (
    <div className="space-y-5">
      <div className="flex flex-col md:flex-row gap-3 items-center justify-between">
        <div className="relative w-full md:w-80">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input 
            type="text" 
            placeholder="Buscar transações..."
            className="w-full pl-9 pr-4 py-1.5 bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex gap-2 w-full md:w-auto">
          <div className="flex border border-slate-200 rounded-xl bg-white overflow-hidden text-xs">
            <button onClick={() => setTypeFilter('all')} className={`px-3 py-1.5 font-medium ${typeFilter === 'all' ? 'bg-slate-100 text-slate-900' : 'text-slate-500'}`}>Todos</button>
            <button onClick={() => setTypeFilter('income')} className={`px-3 py-1.5 font-medium ${typeFilter === 'income' ? 'bg-emerald-50 text-emerald-600' : 'text-slate-500'}`}>Receitas</button>
            <button onClick={() => setTypeFilter('expense')} className={`px-3 py-1.5 font-medium ${typeFilter === 'expense' ? 'bg-red-50 text-red-600' : 'text-slate-500'}`}>Despesas</button>
          </div>
          <button 
            onClick={() => setShowAddModal(true)}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-1.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 font-medium transition-colors text-sm"
          >
            <Plus className="w-4 h-4" />
            Nova
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-5 py-3 text-xs font-semibold text-slate-600">Descrição</th>
              <th className="px-5 py-3 text-xs font-semibold text-slate-600">Pote / Categoria</th>
              <th className="px-5 py-3 text-xs font-semibold text-slate-600">Data</th>
              <th className="px-5 py-3 text-xs font-semibold text-slate-600 text-right">Valor</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredTransactions.map(t => (
              <tr key={t.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-5 py-3">
                  <div className="flex items-center gap-2">
                    {t.type === 'income' ? <ArrowUpCircle className="w-4 h-4 text-emerald-500" /> : <ArrowDownCircle className="w-4 h-4 text-red-400" />}
                    <span className="font-medium text-slate-800 text-sm">{t.description}</span>
                  </div>
                </td>
                <td className="px-5 py-3">
                  <div className="flex flex-col">
                    <span className="text-[10px] font-bold text-indigo-600">
                      {t.type === 'income' ? 'Distribuído' : (potes.find(p => p.id === t.poteId)?.name || 'Geral')}
                    </span>
                    <span className="text-[9px] text-slate-400 uppercase tracking-tighter">{t.category}</span>
                  </div>
                </td>
                <td className="px-5 py-3 text-slate-500 text-xs">
                  {new Date(t.date).toLocaleDateString('pt-BR')}
                </td>
                <td className={`px-5 py-3 text-right font-bold text-sm ${t.type === 'income' ? 'text-emerald-600' : 'text-slate-700'}`}>
                  {t.type === 'income' ? '+' : '-'} R$ {t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50">
          <div className="bg-white rounded-2xl w-full max-w-sm p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-5">
              <h3 className="text-lg font-bold">Adicionar Transação</h3>
              <button onClick={() => setShowAddModal(false)}><X className="w-5 h-5 text-slate-400" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-3.5">
              <div>
                <label className="block text-xs font-medium text-slate-700 mb-1">Descrição</label>
                <input type="text" required className="w-full px-3 py-2 border rounded-xl text-sm" value={newTx.description} onChange={e => setNewTx({...newTx, description: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs font-medium text-slate-700 mb-1">Valor (R$)</label>
                  <input type="number" step="0.01" required className="w-full px-3 py-2 border rounded-xl text-sm" value={newTx.amount || ''} onChange={e => setNewTx({...newTx, amount: parseFloat(e.target.value)})} />
                </div>
                <div>
                  <label className="block text-xs font-medium text-slate-700 mb-1">Tipo</label>
                  <select className="w-full px-3 py-2 border rounded-xl text-sm" value={newTx.type} onChange={e => setNewTx({...newTx, type: e.target.value as TransactionType})}>
                    <option value="expense">Despesa</option>
                    <option value="income">Receita</option>
                  </select>
                </div>
              </div>

              {newTx.type === 'expense' && (
                <div>
                  <label className="block text-xs font-medium text-slate-700 mb-1">Pote</label>
                  <select className="w-full px-3 py-2 border rounded-xl bg-indigo-50 text-sm" value={newTx.poteId} onChange={e => setNewTx({...newTx, poteId: e.target.value})}>
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
                </div>
              )}

              <div>
                <label className="block text-xs font-medium text-slate-700 mb-1">Categoria</label>
                <input type="text" required className="w-full px-3 py-2 border rounded-xl text-sm" value={newTx.category} onChange={e => setNewTx({...newTx, category: e.target.value})} />
              </div>
              <div>
                <label className="block text-xs font-medium text-slate-700 mb-1">Data</label>
                <input type="date" required className="w-full px-3 py-2 border rounded-xl text-sm" value={newTx.date} onChange={e => setNewTx({...newTx, date: e.target.value})} />
              </div>
              <button type="submit" className="w-full py-2.5 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition-colors text-sm">Salvar</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  Target, 
  Wallet, 
  BrainCircuit, 
  Plus, 
  Menu,
  X,
  Archive
} from 'lucide-react';
import { AppView, Transaction, Budget, FinancialGoal, Jar } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Necessidades Básicas', percentage: 50, balance: 2500 },
  { id: '2', name: 'Investimentos', percentage: 30, balance: 1500 },
  { id: '3', name: 'Lazer', percentage: 20, balance: 1000 },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : [
      { id: '1', description: 'Salário Mensal', amount: 5000, category: 'Salário', date: '2023-11-01', type: 'income' },
      { id: '2', description: 'Aluguel', amount: 1500, category: 'Moradia', date: '2023-11-05', type: 'expense', poteId: '1' },
    ];
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [budgets, setBudgets] = useState<Budget[]>(() => {
    const saved = localStorage.getItem('zen_budgets');
    return saved ? JSON.parse(saved) : [
      { category: 'Moradia', limit: 1600, spent: 1500 },
      { category: 'Alimentação', limit: 800, spent: 0 },
    ];
  });

  const [goals, setGoals] = useState<FinancialGoal[]>(() => {
    const saved = localStorage.getItem('zen_goals');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Reserva de Emergência', targetAmount: 15000, currentAmount: 3000, deadline: '2024-12-31' },
    ];
  });

  // Persistência em "Banco de Dados" (LocalStorage)
  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [transactions, potes, budgets, goals]);

  const financialData = useMemo(() => ({
    transactions,
    budgets,
    goals,
    potes
  }), [transactions, budgets, goals, potes]);

  // Lógica de atualização de potes centralizada
  const updatePotesForNewTransaction = (t: Transaction, jars: Jar[]) => {
    return jars.map(pote => {
      if (t.type === 'income') {
        const share = t.amount * (pote.percentage / 100);
        return { ...pote, balance: pote.balance + share };
      } else {
        if (t.poteId === pote.id) {
          return { ...pote, balance: pote.balance - t.amount };
        }
      }
      return pote;
    });
  };

  const updatePotesForRemovedTransaction = (t: Transaction, jars: Jar[]) => {
    return jars.map(pote => {
      if (t.type === 'income') {
        const share = t.amount * (pote.percentage / 100);
        return { ...pote, balance: pote.balance - share };
      } else {
        if (t.poteId === pote.id) {
          return { ...pote, balance: pote.balance + t.amount };
        }
      }
      return pote;
    });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    setPotes(updatePotesForNewTransaction(t, potes));
  };

  const handleDeleteTransaction = (id: string) => {
    const txToDelete = transactions.find(t => t.id === id);
    if (!txToDelete) return;

    if (confirm('Tem certeza que deseja excluir esta movimentação? Os saldos dos potes serão ajustados.')) {
      setTransactions(transactions.filter(t => t.id !== id));
      setPotes(updatePotesForRemovedTransaction(txToDelete, potes));
    }
  };

  const handleEditTransaction = (updatedTx: Transaction) => {
    const oldTx = transactions.find(t => t.id === updatedTx.id);
    if (!oldTx) return;

    // Para simplificar a lógica de saldo, primeiro "revertemos" a transação antiga e depois "aplicamos" a nova
    let tempPotes = updatePotesForRemovedTransaction(oldTx, potes);
    let finalPotes = updatePotesForNewTransaction(updatedTx, tempPotes);

    setTransactions(transactions.map(t => t.id === updatedTx.id ? updatedTx : t));
    setPotes(finalPotes);
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'potes', label: 'Potes', icon: Archive },
    { id: 'transactions', label: 'Transações', icon: Receipt },
    { id: 'budgets', label: 'Orçamentos', icon: Wallet },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-slate-50">
      <aside className={`fixed md:sticky top-0 h-screen z-30 transition-all duration-300 ${isSidebarOpen ? 'w-56 translate-x-0' : 'w-0 -translate-x-full md:w-16 md:translate-x-0'} bg-indigo-900 text-white flex flex-col overflow-hidden`}>
        <div className="p-5 flex items-center gap-2">
          <div className="bg-white/10 p-1.5 rounded-lg"><BrainCircuit className="w-5 h-5 text-indigo-300" /></div>
          {isSidebarOpen && <span className="text-lg font-bold tracking-tight">ZenFinance</span>}
        </div>
        <nav className="flex-1 px-2 mt-4 space-y-0.5">
          {navItems.map((item) => (
            <button key={item.id} onClick={() => setView(item.id as AppView)} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors ${view === item.id ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800/50'}`}>
