import React, { useState } from 'react';
import { Search, Plus, Minus, ArrowUpCircle, ArrowDownCircle, X, Trash2, Edit2, Check } from 'lucide-react';
import { Transaction, TransactionType, Jar } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
}

export default function Transactions({ transactions, potes, onAdd, onDelete, onEdit }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '',
    amount: 0,
    category: 'Outros',
    type: 'expense',
    date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : ''
  });

  const filteredTransactions = transactions.filter(t => {
    const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          t.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = typeFilter === 'all' || t.type === typeFilter;
    return matchesSearch && matchesType;
  });

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '',
      amount: 0,
      category: type === 'income' ? 'Salário' : 'Alimentação',
      type: type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : undefined
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount) return;

    if (modalType === 'add') {
      onAdd({
        ...currentTx as Transaction,
        id: Math.random().toString(36).substr(2, 9)
      });
    } else if (modalType === 'edit') {
      onEdit(currentTx as Transaction);
    }

    setModalType(null);
  };

  return (
    <div className="space-y-5">
      {/* Botões de Ação Rápida */}
      <div className="grid grid-cols-2 gap-3">
        <button 
          onClick={() => handleOpenAdd('income')}
          className="flex items-center justify-center gap-2 py-3 bg-emerald-500 text-white rounded-2xl hover:bg-emerald-600 transition-all font-bold shadow-lg shadow-emerald-100"
        >
          <Plus className="w-5 h-5" /> Nova Entrada
        </button>
        <button 
          onClick={() => handleOpenAdd('expense')}
          className="flex items-center justify-center gap-2 py-3 bg-red-500 text-white rounded-2xl hover:bg-red-600 transition-all font-bold shadow-lg shadow-red-100"
        >
          <Minus className="w-5 h-5" /> Nova Saída
        </button>
      </div>

      <div className="flex flex-col md:flex-row gap-3 items-center justify-between pt-2">
        <div className="relative w-full md:w-80">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input 
            type="text" 
            placeholder="Buscar transações..."
            className="w-full pl-9 pr-4 py-1.5 bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex border border-slate-200 rounded-xl bg-white overflow-hidden text-xs">
          <button onClick={() => setTypeFilter('all')} className={`px-4 py-1.5 font-medium ${typeFilter === 'all' ? 'bg-slate-100 text-slate-900' : 'text-slate-500'}`}>Todos</button>
          <button onClick={() => setTypeFilter('income')} className={`px-4 py-1.5 font-medium ${typeFilter === 'income' ? 'bg-emerald-50 text-emerald-600' : 'text-slate-500'}`}>Receitas</button>
          <button onClick={() => setTypeFilter('expense')} className={`px-4 py-1.5 font-medium ${typeFilter === 'expense' ? 'bg-red-50 text-red-600' : 'text-slate-500'}`}>Despesas</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[600px]">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
                <th className="px-5 py-3 text-xs font-semibold text-slate-600">Descrição</th>
                <th className="px-5 py-3 text-xs font-semibold text-slate-600">Origem / Destino</th>
                <th className="px-5 py-3 text-xs font-semibold text-slate-600">Data</th>
                <th className="px-5 py-3 text-xs font-semibold text-slate-600 text-right">Valor</th>
                <th className="px-5 py-3 text-xs font-semibold text-slate-600 text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTransactions.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/50 group transition-colors">
                  <td className="px-5 py-3">
                    <div className="flex items-center gap-2">
                      {t.type === 'income' ? <ArrowUpCircle className="w-4 h-4 text-emerald-500" /> : <ArrowDownCircle className="w-4 h-4 text-red-400" />}
                      <span className="font-medium text-slate-800 text-sm">{t.description}</span>
                    </div>
                  </td>
                  <td className="px-5 py-3">
                    <div className="flex flex-col">
                      <span className="text-[10px] font-bold text-indigo-600">
                        {t.type === 'income' ? 'Divisão Automática' : (potes.find(p => p.id === t.poteId)?.name || 'Geral')}
                      </span>
                      <span className="text-[9px] text-slate-400 uppercase tracking-tighter">{t.category}</span>
                    </div>
                  </td>
                  <td className="px-5 py-3 text-slate-500 text-xs">
                    {new Date(t.date).toLocaleDateString('pt-BR')}
                  </td>
                  <td className={`px-5 py-3 text-right font-bold text-sm ${t.type === 'income' ? 'text-emerald-600' : 'text-slate-700'}`}>
                    {t.type === 'income' ? '+' : '-'} R$ {t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </td>
                  <td className="px-5 py-3">
                    <div className="flex justify-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => handleOpenEdit(t)} className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors">
                        <Edit2 className="w-3.5 h-3.5" />
                      </button>
                      <button onClick={() => onDelete(t.id)} className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors">
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
              {filteredTransactions.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-5 py-10 text-center text-slate-400 text-sm italic">
                    Nenhuma transação encontrada.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {(modalType === 'add' || modalType === 'edit') && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-sm p-6 shadow-2xl animate-in fade-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-5">
              <h3 className="text-lg font-bold text-slate-800">
                {modalType === 'add' ? (currentTx.type === 'income' ? 'Nova Entrada' : 'Nova Saída') : 'Editar Registro'}
              </h3>
              <button onClick={() => setModalType(null)} className="p-1 hover:bg-slate-100 rounded-full"><X className="w-5 h-5 text-slate-400" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Descrição</label>
                <input 
                  type="text" required 
                  placeholder="ex: Salário, Almoço, Netflix..."
                  className="w-full px-3 py-2 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none" 
                  value={currentTx.description} 
                  onChange={e => setCurrentTx({...currentTx, description: e.target.value})} 
                />
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Valor (R$)</label>
                  <input 
                    type="number" step="0.01" required 
                    className="w-full px-3 py-2 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={currentTx.amount || ''} 
                    onChange={e => setCurrentTx({...currentTx, amount: parseFloat(e.target.value)})} 
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Data</label>
                  <input 
                    type="date" required 
                    className="w-full px-3 py-2 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={currentTx.date} 
                    onChange={e => setCurrentTx({...currentTx, date: e.target.value})} 
                  />
                </div>
              </div>

              {currentTx.type === 'expense' && (
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Retirar de qual Pote?</label>
                  <select 
                    className="w-full px-3 py-2 border border-slate-200 rounded-xl bg-slate-50 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={currentTx.poteId} 
                    onChange={e => setCurrentTx({...currentTx, poteId: e.target.value})}
                  >
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name} (Saldo: R$ {p.balance.toFixed(2)})</option>)}
                  </select>
                </div>
              )}

              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Categoria</label>
                <input 
                  type="text" required 
                  className="w-full px-3 py-2 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none" 
                  value={currentTx.category} 
                  onChange={e => setCurrentTx({...currentTx, category: e.target.value})} 
                />
              </div>

              <div className="flex gap-2 pt-2">
                <button type="button" onClick={() => setModalType(null)} className="flex-1 py-2.5 text-slate-500 font-bold text-sm hover:bg-slate-50 rounded-xl transition-colors">Cancelar</button>
                <button type="submit" className={`flex-1 py-2.5 text-white font-bold rounded-xl transition-all flex items-center justify-center gap-2 text-sm ${currentTx.type === 'income' ? 'bg-emerald-500 hover:bg-emerald-600 shadow-emerald-100' : 'bg-red-500 hover:bg-red-600 shadow-red-100'} shadow-lg`}>
                  <Check className="w-4 h-4" /> {modalType === 'add' ? 'Confirmar' : 'Salvar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  Target, 
  Wallet, 
  BrainCircuit, 
  Plus, 
  Menu,
  X,
  Archive
} from 'lucide-react';
import { AppView, Transaction, Budget, FinancialGoal, Jar } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Necessidades Básicas', percentage: 50, balance: 2500 },
  { id: '2', name: 'Investimentos', percentage: 30, balance: 1500 },
  { id: '3', name: 'Lazer', percentage: 20, balance: 1000 },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : [
      { id: '1', description: 'Salário Mensal', amount: 5000, category: 'Salário', date: '2023-11-01', type: 'income' },
      { id: '2', description: 'Aluguel', amount: 1500, category: 'Moradia', date: '2023-11-05', type: 'expense', poteId: '1' },
    ];
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [budgets, setBudgets] = useState<Budget[]>(() => {
    const saved = localStorage.getItem('zen_budgets');
    return saved ? JSON.parse(saved) : [
      { category: 'Moradia', limit: 1600, spent: 1500 },
      { category: 'Alimentação', limit: 800, spent: 0 },
    ];
  });

  const [goals, setGoals] = useState<FinancialGoal[]>(() => {
    const saved = localStorage.getItem('zen_goals');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Reserva de Emergência', targetAmount: 15000, currentAmount: 3000, deadline: '2024-12-31' },
    ];
  });

  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [transactions, potes, budgets, goals]);

  const financialData = useMemo(() => ({ transactions, budgets, goals, potes }), [transactions, budgets, goals, potes]);

  const updatePotesForNewTransaction = (t: Transaction, jars: Jar[]) => {
    return jars.map(pote => {
      if (t.type === 'income') {
        const share = t.amount * (pote.percentage / 100);
        return { ...pote, balance: pote.balance + share };
      } else if (t.poteId === pote.id) {
        return { ...pote, balance: pote.balance - t.amount };
      }
      return pote;
    });
  };

  const updatePotesForRemovedTransaction = (t: Transaction, jars: Jar[]) => {
    return jars.map(pote => {
      if (t.type === 'income') {
        const share = t.amount * (pote.percentage / 100);
        return { ...pote, balance: pote.balance - share };
      } else if (t.poteId === pote.id) {
        return { ...pote, balance: pote.balance + t.amount };
      }
      return pote;
    });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    setPotes(updatePotesForNewTransaction(t, potes));
  };

  const handleDeleteTransaction = (id: string) => {
    const txToDelete = transactions.find(t => t.id === id);
    if (!txToDelete) return;
    if (confirm('Deseja excluir esta movimentação?')) {
      setTransactions(transactions.filter(t => t.id !== id));
      setPotes(updatePotesForRemovedTransaction(txToDelete, potes));
    }
  };

  const handleEditTransaction = (updatedTx: Transaction) => {
    const oldTx = transactions.find(t => t.id === updatedTx.id);
    if (!oldTx) return;
    let tempPotes = updatePotesForRemovedTransaction(oldTx, potes);
    let finalPotes = updatePotesForNewTransaction(updatedTx, tempPotes);
    setTransactions(transactions.map(t => t.id === updatedTx.id ? updatedTx : t));
    setPotes(finalPotes);
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'potes', label: 'Potes', icon: Archive },
    { id: 'transactions', label: 'Transações', icon: Receipt },
    { id: 'budgets', label: 'Orçamentos', icon: Wallet },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100">
      <aside className={`fixed md:sticky top-0 h-screen z-30 transition-all duration-300 ${isSidebarOpen ? 'w-56 translate-x-0' : 'w-0 -translate-x-full md:w-16 md:translate-x-0'} bg-[#0a0c14] border-r border-slate-800 flex flex-col overflow-hidden`}>
        <div className="p-5 flex items-center gap-2">
          <div className="bg-indigo-500/10 p-2 rounded-xl border border-indigo-500/20"><BrainCircuit className="w-5 h-5 text-indigo-400" /></div>
          {isSidebarOpen && <span className="text-lg font-bold tracking-tighter text-white">ZenFinance</span>}
        </div>
        <nav className="flex-1 px-2 mt-4 space-y-1">
          {navItems.map((item) => (
            <button key={item.id} onClick={() => setView(item.id as AppView)} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${view === item.id ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/20' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800/40'}`}>
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {isSidebarOpen && <span className="font-semibold text-sm">{item.label}</span>}
            </button>
          ))}
        </nav>
        <div className="p-3 border-t border-slate-800">
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-full flex items-center justify-center p-2 rounded-lg hover:bg-slate-800 transition-colors">
            {isSidebarOpen ? <X className="w-4 h-4 text-slate-500" /> : <Menu className="w-4 h-4 text-slate-500" />}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        <header className="h-14 glass sticky top-0 z-10 px-5 flex items-center justify-between">
          <h1 className="text-lg font-bold text-white capitalize tracking-tight">{navItems.find(i => i.id === view)?.label}</h1>
          <div className="flex items-center gap-3">
             <div className="flex items-center gap-2 bg-slate-800/40 px-3 py-1 rounded-full border border-slate-700/50">
                <div className="w-2 h-2 bg-indigo-500 rounded-full animate-pulse"></div>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Premium AI</span>
             </div>
             <img src="https://picsum.photos/seed/finance/32/32" className="w-8 h-8 rounded-full border-2 border-slate-700 shadow-xl" alt="avatar" />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && (
            <Transactions 
              transactions={transactions} 
              potes={potes} 
              onAdd={handleAddTransaction} 
              onDelete={handleDeleteTransaction}
              onEdit={handleEditTransaction}
            />
          )}
          {view === 'budgets' && <Budgets budgets={budgets} onUpdate={(b) => setBudgets(budgets.map(item => item.category === b.category ? b : item))} />}
          {view === 'goals' && <Goals goals={goals} onAdd={(g) => setGoals([...goals, g])} />}
          {view === 'potes' && <Potes potes={potes} onUpdate={setPotes} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

