      onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    } else if (modalType === 'edit') {
      onEdit(currentTx as Transaction);
    }
    setModalType(null);
  };

  return (
    <div className="space-y-6">
      {/* Quick Action Buttons */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <button 
          onClick={() => handleOpenAdd('income')}
          className="group relative flex items-center justify-center gap-3 py-4 bg-emerald-500/10 border border-emerald-500/30 text-emerald-400 rounded-3xl hover:bg-emerald-500/20 transition-all font-bold shadow-xl shadow-emerald-500/5"
        >
          <div className="bg-emerald-400 p-1.5 rounded-full text-emerald-950 group-hover:scale-110 transition-transform"><Plus className="w-5 h-5" /></div>
          Nova Entrada
        </button>
        <button 
          onClick={() => handleOpenAdd('expense')}
          className="group relative flex items-center justify-center gap-3 py-4 bg-rose-500/10 border border-rose-500/30 text-rose-400 rounded-3xl hover:bg-rose-500/20 transition-all font-bold shadow-xl shadow-rose-500/5"
        >
          <div className="bg-rose-400 p-1.5 rounded-full text-rose-950 group-hover:scale-110 transition-transform"><Minus className="w-5 h-5" /></div>
          Nova Saída
        </button>
      </div>

      <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="relative w-full md:w-80">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
          <input 
            type="text" 
            placeholder="Buscar movimentos..."
            className="w-full pl-10 pr-4 py-2 bg-slate-900/40 border border-slate-800 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm text-slate-100 placeholder-slate-600"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex bg-slate-900/60 p-1 rounded-2xl border border-slate-800">
          {['all', 'income', 'expense'].map((f) => (
            <button 
              key={f}
              onClick={() => setTypeFilter(f as any)} 
              className={`px-4 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${typeFilter === f ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
            >
              {f === 'all' ? 'Tudo' : f === 'income' ? 'Receitas' : 'Despesas'}
            </button>
          ))}
        </div>
      </div>

      <div className="bg-[#111827]/40 backdrop-blur-md rounded-3xl border border-white/5 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[650px]">
            <thead>
              <tr className="bg-white/5 border-b border-white/5">
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">Descrição</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">Pote / Canal</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">Data</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest text-right">Valor</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {filteredTransactions.map(t => (
                <tr key={t.id} className="hover:bg-white/5 group transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className={`p-1.5 rounded-lg ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                        {t.type === 'income' ? <ArrowUpCircle className="w-4 h-4" /> : <ArrowDownCircle className="w-4 h-4" />}
                      </div>
                      <span className="font-semibold text-slate-200 text-sm tracking-tight">{t.description}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-indigo-400 uppercase">
                        {t.type === 'income' ? 'Sistema Automático' : (potes.find(p => p.id === t.poteId)?.name || 'Geral')}
                      </span>
                      <span className="text-[9px] text-slate-500 font-bold uppercase tracking-tighter">{t.category}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-slate-500 text-xs font-medium">
                    {new Date(t.date).toLocaleDateString('pt-BR')}
                  </td>
                  <td className={`px-6 py-4 text-right font-bold text-sm tracking-tighter ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-200'}`}>
                    {t.type === 'income' ? '+' : '-'} R$ {t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => handleOpenEdit(t)} className="p-2 text-slate-500 hover:text-indigo-400 hover:bg-indigo-400/10 rounded-xl transition-all"><Edit2 className="w-4 h-4" /></button>
                      <button onClick={() => onDelete(t.id)} className="p-2 text-slate-500 hover:text-rose-500 hover:bg-rose-500/10 rounded-xl transition-all"><Trash2 className="w-4 h-4" /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {modalType && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-[#1e293b] rounded-3xl w-full max-w-sm p-8 border border-white/10 shadow-2xl animate-in fade-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-white tracking-tight">
                {modalType === 'add' ? (currentTx.type === 'income' ? 'Nova Entrada' : 'Nova Saída') : 'Editar Registro'}
              </h3>
              <button onClick={() => setModalType(null)} className="p-1 hover:bg-white/5 rounded-full"><X className="w-5 h-5 text-slate-500" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Descrição</label>
                <input type="text" required className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentTx.description} onChange={e => setCurrentTx({...currentTx, description: e.target.value})} />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Valor (R$)</label>
                  <input type="number" step="0.01" required className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentTx.amount || ''} onChange={e => setCurrentTx({...currentTx, amount: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Data</label>
                  <input type="date" required className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentTx.date} onChange={e => setCurrentTx({...currentTx, date: e.target.value})} />
                </div>
              </div>

              {currentTx.type === 'expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Fonte de Origem (Pote)</label>
                  <select className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentTx.poteId} onChange={e => setCurrentTx({...currentTx, poteId: e.target.value})}>
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Categoria</label>
                <input type="text" required className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentTx.category} onChange={e => setCurrentTx({...currentTx, category: e.target.value})} />
              </div>

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setModalType(null)} className="flex-1 py-3 text-slate-400 font-bold text-sm hover:text-white transition-colors">Cancelar</button>
                <button type="submit" className={`flex-1 py-3 text-white font-bold rounded-2xl transition-all flex items-center justify-center gap-2 text-sm ${currentTx.type === 'income' ? 'bg-emerald-500 hover:bg-emerald-600' : 'bg-rose-500 hover:bg-rose-600'} shadow-2xl`}>
                  <Check className="w-4 h-4" /> {modalType === 'add' ? 'Salvar' : 'Atualizar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { Jar } from '../types';
import { Plus, Trash2, Edit2, Archive, X, Save } from 'lucide-react';

interface PotesProps {
  potes: Jar[];
  onUpdate: (potes: Jar[]) => void;
}

export default function Potes({ potes, onUpdate }: PotesProps) {
  const [showModal, setShowModal] = useState<'add' | 'edit' | null>(null);
  const [currentPote, setCurrentPote] = useState<Partial<Jar>>({ name: '', percentage: 0 });

  const totalPercentage = potes.reduce((acc, p) => acc + p.percentage, 0);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const otherPotes = showModal === 'edit' ? potes.filter(p => p.id !== currentPote.id) : potes;
    const currentTotal = otherPotes.reduce((acc, p) => acc + p.percentage, 0);
    if (currentTotal + (currentPote.percentage || 0) > 100) { alert("Limite de 100% excedido!"); return; }

    if (showModal === 'add') {
      const pote: Jar = { id: Math.random().toString(36).substr(2, 9), name: currentPote.name || 'Pote', percentage: currentPote.percentage || 0, balance: 0 };
      onUpdate([...potes, pote]);
    } else {
      onUpdate(potes.map(p => p.id === currentPote.id ? { ...p, ...currentPote } as Jar : p));
    }
    setShowModal(null);
  };

  return (
    <div className="space-y-6">
      <div className="bg-[#111827]/40 p-5 rounded-3xl border border-white/5 flex items-center justify-between backdrop-blur-md">
        <div>
          <h2 className="text-lg font-bold text-white tracking-tight">Arquitetura Financeira</h2>
          <p className="text-slate-500 text-[11px] font-black uppercase tracking-widest mt-1">Configurado: <span className={totalPercentage > 100 ? 'text-rose-500' : 'text-indigo-400'}>{totalPercentage}%</span> / 100%</p>
        </div>
        <button 
          onClick={() => { setCurrentPote({ name: '', percentage: 0 }); setShowModal('add'); }}
          className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all text-sm shadow-xl shadow-indigo-500/10"
        >
          <Plus className="w-4 h-4" /> Criar Novo Pote
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {potes.map((pote) => (
          <div key={pote.id} className="bg-[#0f172a]/80 p-6 rounded-3xl shadow-2xl border border-white/5 group relative overflow-hidden transition-all hover:-translate-y-1">
            <div className="absolute top-0 right-0 p-4 opacity-0 group-hover:opacity-100 transition-all flex gap-1">
              <button onClick={() => { setCurrentPote(pote); setShowModal('edit'); }} className="p-2 text-slate-500 hover:text-indigo-400 hover:bg-indigo-400/10 rounded-xl"><Edit2 className="w-4 h-4" /></button>
              <button onClick={() => confirm('Excluir?') && onUpdate(potes.filter(p => p.id !== pote.id))} className="p-2 text-slate-500 hover:text-rose-500 hover:bg-rose-500/10 rounded-xl"><Trash2 className="w-4 h-4" /></button>
            </div>

            <div className="bg-indigo-500/10 w-12 h-12 flex items-center justify-center rounded-2xl border border-indigo-500/20 mb-5">
              <Archive className="w-6 h-6 text-indigo-400" />
            </div>

            <h3 className="text-lg font-bold text-white mb-1 tracking-tight">{pote.name}</h3>
            <span className="inline-block px-2 py-0.5 bg-indigo-400/10 text-indigo-400 text-[9px] font-black rounded-lg uppercase tracking-widest mb-4">Aporte Fixo: {pote.percentage}%</span>

            <div className="mb-5">
              <p className="text-[10px] text-slate-500 uppercase font-black tracking-[0.2em] mb-1">Saldo Líquido</p>
              <p className={`text-3xl font-bold tracking-tighter ${pote.balance >= 0 ? 'text-white' : 'text-rose-500'}`}>
                R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </p>
            </div>

            <div className="w-full bg-slate-800 h-2 rounded-full overflow-hidden border border-white/5">
                <div 
                  className="bg-indigo-500 h-full transition-all duration-700 shadow-[0_0_12px_rgba(99,102,241,0.6)]" 
                  style={{ width: `${pote.percentage}%` }} 
                />
            </div>
          </div>
        ))}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
          <div className="bg-[#1e293b] rounded-3xl w-full max-w-sm p-8 border border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-white">{showModal === 'add' ? 'Configurar Pote' : 'Redefinir Pote'}</h3>
              <button onClick={() => setShowModal(null)}><X className="w-5 h-5 text-slate-500" /></button>
            </div>
            <form onSubmit={handleSave} className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Nome Identificador</label>
                <input type="text" required className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentPote.name} onChange={e => setCurrentPote({...currentPote, name: e.target.value})} />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Absorção Automática (%)</label>
                <div className="relative">
                  <input type="number" required min="1" max="100" className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentPote.percentage || ''} onChange={e => setCurrentPote({...currentPote, percentage: parseInt(e.target.value)})} />
                  <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 font-black">%</span>
                </div>
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowModal(null)} className="flex-1 py-3 text-slate-500 font-bold hover:text-white transition-colors">Abortar</button>
                <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 shadow-xl transition-all">
                  <Save className="w-4 h-4" /> Confirmar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  Target, 
  Wallet, 
  BrainCircuit, 
  Plus, 
  Menu,
  X,
  Archive
} from 'lucide-react';
import { AppView, Transaction, Budget, FinancialGoal, Jar } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Necessidades Básicas', percentage: 50, balance: 2500 },
  { id: '2', name: 'Investimentos', percentage: 30, balance: 1500 },
  { id: '3', name: 'Lazer', percentage: 20, balance: 1000 },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : [
      { id: '1', description: 'Salário Mensal', amount: 5000, category: 'Salário', date: '2023-11-01', type: 'income' },
      { id: '2', description: 'Aluguel', amount: 1500, category: 'Moradia', date: '2023-11-05', type: 'expense', poteId: '1' },
    ];
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [budgets, setBudgets] = useState<Budget[]>(() => {
    const saved = localStorage.getItem('zen_budgets');
    return saved ? JSON.parse(saved) : [
      { category: 'Moradia', limit: 1600, spent: 1500 },
      { category: 'Alimentação', limit: 800, spent: 0 },
    ];
  });

  const [goals, setGoals] = useState<FinancialGoal[]>(() => {
    const saved = localStorage.getItem('zen_goals');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Reserva de Emergência', targetAmount: 15000, currentAmount: 3000, deadline: '2024-12-31' },
    ];
  });

  // Persistência automática
  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [transactions, potes, budgets, goals]);

  const financialData = useMemo(() => ({ transactions, budgets, goals, potes }), [transactions, budgets, goals, potes]);

  // Utilitários de cálculo de pote
  const calculatePotesUpdate = (t: Transaction, currentJars: Jar[], isRemoval: boolean = false) => {
    const multiplier = isRemoval ? -1 : 1;
    return currentJars.map(pote => {
      if (t.type === 'income') {
        const share = t.amount * (pote.percentage / 100);
        return { ...pote, balance: pote.balance + (share * multiplier) };
      } else if (t.poteId === pote.id) {
        // Se for despesa, subtraímos do pote. Se for remoção de despesa, somamos de volta.
        return { ...pote, balance: pote.balance - (t.amount * multiplier) };
      }
      return pote;
    });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions(prev => [t, ...prev]);
    setPotes(prev => calculatePotesUpdate(t, prev, false));
  };

  const handleDeleteTransaction = (id: string) => {
    const txToDelete = transactions.find(t => t.id === id);
    if (!txToDelete) return;

    if (window.confirm('Deseja excluir permanentemente esta movimentação? Os saldos serão recalculados.')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
      setPotes(prev => calculatePotesUpdate(txToDelete, prev, true));
    }
  };

  const handleEditTransaction = (updatedTx: Transaction) => {
    const oldTx = transactions.find(t => t.id === updatedTx.id);
    if (!oldTx) return;

    setTransactions(prev => prev.map(t => t.id === updatedTx.id ? updatedTx : t));

    setPotes(prev => {
      // Reverte a antiga e aplica a nova
      const reverted = calculatePotesUpdate(oldTx, prev, true);
      return calculatePotesUpdate(updatedTx, reverted, false);
    });
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'potes', label: 'Potes', icon: Archive },
    { id: 'transactions', label: 'Transações', icon: Receipt },
    { id: 'budgets', label: 'Orçamentos', icon: Wallet },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100">
      <aside className={`fixed md:sticky top-0 h-screen z-30 transition-all duration-300 ${isSidebarOpen ? 'w-56 translate-x-0' : 'w-0 -translate-x-full md:w-16 md:translate-x-0'} bg-[#0a0c14] border-r border-slate-800 flex flex-col overflow-hidden`}>
        <div className="p-5 flex items-center gap-2">
          <div className="bg-indigo-500/10 p-2 rounded-xl border border-indigo-500/20"><BrainCircuit className="w-5 h-5 text-indigo-400" /></div>
          {isSidebarOpen && <span className="text-lg font-bold tracking-tighter text-white">ZenFinance</span>}
        </div>
        <nav className="flex-1 px-2 mt-4 space-y-1">
          {navItems.map((item) => (
            <button key={item.id} onClick={() => setView(item.id as AppView)} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${view === item.id ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/20' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800/40'}`}>
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {isSidebarOpen && <span className="font-semibold text-sm">{item.label}</span>}
            </button>
          ))}
        </nav>
        <div className="p-3 border-t border-slate-800">
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-full flex items-center justify-center p-2 rounded-lg hover:bg-slate-800 transition-colors">
            {isSidebarOpen ? <X className="w-4 h-4 text-slate-500" /> : <Menu className="w-4 h-4 text-slate-500" />}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        <header className="h-14 glass sticky top-0 z-10 px-5 flex items-center justify-between">
          <h1 className="text-lg font-bold text-white capitalize tracking-tight">{navItems.find(i => i.id === view)?.label}</h1>
          <div className="flex items-center gap-3">
             <div className="flex items-center gap-2 bg-slate-800/40 px-3 py-1 rounded-full border border-slate-700/50">
                <div className="w-2 h-2 bg-indigo-500 rounded-full animate-pulse"></div>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Premium AI</span>
             </div>
             <img src="https://picsum.photos/seed/finance/32/32" className="w-8 h-8 rounded-full border-2 border-slate-700 shadow-xl" alt="avatar" />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && (
            <Transactions 
              transactions={transactions} 
              potes={potes} 
              onAdd={handleAddTransaction} 
              onDelete={handleDeleteTransaction}
              onEdit={handleEditTransaction}
            />
          )}
          {view === 'budgets' && <Budgets budgets={budgets} onUpdate={(b) => setBudgets(budgets.map(item => item.category === b.category ? b : item))} />}
          {view === 'goals' && <Goals goals={goals} onAdd={(g) => setGoals([...goals, g])} />}
          {view === 'potes' && <Potes potes={potes} onUpdate={setPotes} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Search, Plus, Minus, ArrowUpCircle, ArrowDownCircle, X, Trash2, Edit2, Check } from 'lucide-react';
import { Transaction, TransactionType, Jar } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
}

export default function Transactions({ transactions, potes, onAdd, onDelete, onEdit }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '', amount: 0, category: 'Outros', type: 'expense', date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : ''
  });

  const filteredTransactions = transactions.filter(t => {
    const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          t.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = typeFilter === 'all' || t.type === typeFilter;
    return matchesSearch && matchesType;
  });

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '', amount: 0, category: type === 'income' ? 'Salário' : 'Lazer', type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : undefined
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount) return;
    if (modalType === 'add') {
      onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    } else if (modalType === 'edit') {
      onEdit(currentTx as Transaction);
    }
    setModalType(null);
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <button 
          onClick={() => handleOpenAdd('income')}
          className="group relative flex items-center justify-center gap-3 py-4 bg-emerald-500/10 border border-emerald-500/30 text-emerald-400 rounded-3xl hover:bg-emerald-500/20 transition-all font-bold shadow-xl shadow-emerald-500/5"
        >
          <div className="bg-emerald-400 p-1.5 rounded-full text-emerald-950 group-hover:scale-110 transition-transform"><Plus className="w-5 h-5" /></div>
          Nova Entrada
        </button>
        <button 
          onClick={() => handleOpenAdd('expense')}
          className="group relative flex items-center justify-center gap-3 py-4 bg-rose-500/10 border border-rose-500/30 text-rose-400 rounded-3xl hover:bg-rose-500/20 transition-all font-bold shadow-xl shadow-rose-500/5"
        >
          <div className="bg-rose-400 p-1.5 rounded-full text-rose-950 group-hover:scale-110 transition-transform"><Minus className="w-5 h-5" /></div>
          Nova Saída
        </button>
      </div>

      <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="relative w-full md:w-80">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
          <input 
            type="text" 
            placeholder="Buscar movimentos..."
            className="w-full pl-10 pr-4 py-2 bg-slate-900/40 border border-slate-800 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm text-slate-100 placeholder-slate-600"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex bg-slate-900/60 p-1 rounded-2xl border border-slate-800">
          {['all', 'income', 'expense'].map((f) => (
            <button 
              key={f}
              onClick={() => setTypeFilter(f as any)} 
              className={`px-4 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${typeFilter === f ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
            >
              {f === 'all' ? 'Tudo' : f === 'income' ? 'Receitas' : 'Despesas'}
            </button>
          ))}
        </div>
      </div>

      <div className="bg-[#111827]/40 backdrop-blur-md rounded-3xl border border-white/5 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[650px]">
            <thead>
              <tr className="bg-white/5 border-b border-white/5">
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">Descrição</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">Pote / Canal</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">Data</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest text-right">Valor</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {filteredTransactions.map(t => (
                <tr key={t.id} className="hover:bg-white/5 group transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className={`p-1.5 rounded-lg ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                        {t.type === 'income' ? <ArrowUpCircle className="w-4 h-4" /> : <ArrowDownCircle className="w-4 h-4" />}
                      </div>
                      <span className="font-semibold text-slate-200 text-sm tracking-tight">{t.description}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-indigo-400 uppercase">
                        {t.type === 'income' ? 'Sistema Automático' : (potes.find(p => p.id === t.poteId)?.name || 'Geral')}
                      </span>
                      <span className="text-[9px] text-slate-500 font-bold uppercase tracking-tighter">{t.category}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-slate-500 text-xs font-medium">
                    {new Date(t.date).toLocaleDateString('pt-BR')}
