              <button onClick={() => setModalType(null)} className="p-1 hover:bg-white/5 rounded-full"><X className="w-5 h-5 text-slate-500" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Descrição</label>
                <input type="text" required className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentTx.description} onChange={e => setCurrentTx({...currentTx, description: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Valor (R$)</label>
                  <input type="number" step="0.01" required className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentTx.amount || ''} onChange={e => setCurrentTx({...currentTx, amount: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Data</label>
                  <input type="date" required className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentTx.date} onChange={e => setCurrentTx({...currentTx, date: e.target.value})} />
                </div>
              </div>
              {currentTx.type === 'expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Fonte de Origem (Pote)</label>
                  <select className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentTx.poteId} onChange={e => setCurrentTx({...currentTx, poteId: e.target.value})}>
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
                </div>
              )}
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Categoria</label>
                <input type="text" required className="w-full px-4 py-2.5 bg-slate-900/50 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentTx.category} onChange={e => setCurrentTx({...currentTx, category: e.target.value})} />
