import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  Target, 
  Wallet, 
  BrainCircuit, 
  Plus, 
  Menu,
  X,
  Archive
} from 'lucide-react';
import { AppView, Transaction, Budget, FinancialGoal, Jar } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Necessidades Básicas', percentage: 50, balance: 2500 },
  { id: '2', name: 'Investimentos', percentage: 30, balance: 1500 },
  { id: '3', name: 'Lazer', percentage: 20, balance: 1000 },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : [
      { id: '1', description: 'Salário Mensal', amount: 5000, category: 'Salário', date: new Date().toISOString().split('T')[0], type: 'income' },
      { id: '2', description: 'Aluguel', amount: 1500, category: 'Moradia', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1' },
    ];
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [budgets, setBudgets] = useState<Budget[]>(() => {
    const saved = localStorage.getItem('zen_budgets');
    return saved ? JSON.parse(saved) : [
      { category: 'Moradia', limit: 1600, spent: 1500 },
      { category: 'Alimentação', limit: 800, spent: 0 },
    ];
  });

  const [goals, setGoals] = useState<FinancialGoal[]>(() => {
    const saved = localStorage.getItem('zen_goals');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Reserva de Emergência', targetAmount: 15000, currentAmount: 3000, deadline: '2024-12-31' },
    ];
  });

  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [transactions, potes, budgets, goals]);

  const financialData = useMemo(() => ({ transactions, budgets, goals, potes }), [transactions, budgets, goals, potes]);

  // Lógica de distribuição e subtração automática
  const calculatePotesUpdate = (t: Transaction, currentJars: Jar[], isRemoval: boolean = false) => {
    const multiplier = isRemoval ? -1 : 1;
    return currentJars.map(pote => {
      if (t.type === 'income') {
        // Se entrou dinheiro, distribui conforme a porcentagem definida no pote
        const share = t.amount * (pote.percentage / 100);
        return { ...pote, balance: pote.balance + (share * multiplier) };
      } else if (t.type === 'expense' && t.poteId === pote.id) {
        // Se saiu dinheiro, retira apenas do pote selecionado
        return { ...pote, balance: pote.balance - (t.amount * multiplier) };
      }
      return pote;
    });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions(prev => [t, ...prev]);
    setPotes(prev => calculatePotesUpdate(t, prev, false));
  };

  const handleDeleteTransaction = (id: string) => {
    const txToDelete = transactions.find(t => t.id === id);
    if (!txToDelete) return;

    if (window.confirm('Excluir esta transação? Os saldos do sistema e dos potes serão atualizados.')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
      setPotes(prev => calculatePotesUpdate(txToDelete, prev, true));
    }
  };

  const handleEditTransaction = (updatedTx: Transaction) => {
    const oldTx = transactions.find(t => t.id === updatedTx.id);
    if (!oldTx) return;

    setTransactions(prev => prev.map(t => t.id === updatedTx.id ? updatedTx : t));

    setPotes(prev => {
      // Reverter o impacto da transação antiga
      const reverted = calculatePotesUpdate(oldTx, prev, true);
      // Aplicar o impacto da nova transação editada
      return calculatePotesUpdate(updatedTx, reverted, false);
    });
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'potes', label: 'Potes', icon: Archive },
    { id: 'transactions', label: 'Transações', icon: Receipt },
    { id: 'budgets', label: 'Orçamentos', icon: Wallet },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100">
      <aside className={`fixed md:sticky top-0 h-screen z-30 transition-all duration-300 ${isSidebarOpen ? 'w-56 translate-x-0' : 'w-0 -translate-x-full md:w-16 md:translate-x-0'} bg-[#0a0c14] border-r border-slate-800 flex flex-col overflow-hidden`}>
        <div className="p-5 flex items-center gap-2">
          <div className="bg-indigo-500/10 p-2 rounded-xl border border-indigo-500/20"><BrainCircuit className="w-5 h-5 text-indigo-400" /></div>
          {isSidebarOpen && <span className="text-lg font-bold tracking-tighter text-white">ZenFinance</span>}
        </div>
        <nav className="flex-1 px-2 mt-4 space-y-1">
          {navItems.map((item) => (
            <button key={item.id} onClick={() => setView(item.id as AppView)} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${view === item.id ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/20' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800/40'}`}>
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {isSidebarOpen && <span className="font-semibold text-sm">{item.label}</span>}
            </button>
          ))}
        </nav>
        <div className="p-3 border-t border-slate-800">
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-full flex items-center justify-center p-2 rounded-lg hover:bg-slate-800 transition-colors">
            {isSidebarOpen ? <X className="w-4 h-4 text-slate-500" /> : <Menu className="w-4 h-4 text-slate-500" />}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        <header className="h-14 glass sticky top-0 z-10 px-5 flex items-center justify-between">
          <h1 className="text-lg font-bold text-white capitalize tracking-tight">{navItems.find(i => i.id === view)?.label}</h1>
          <div className="flex items-center gap-3">
             <div className="flex items-center gap-2 bg-slate-800/40 px-3 py-1 rounded-full border border-slate-700/50">
                <div className="w-2 h-2 bg-indigo-500 rounded-full animate-pulse"></div>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Premium AI</span>
             </div>
             <img src="https://picsum.photos/seed/finance/32/32" className="w-8 h-8 rounded-full border-2 border-slate-700 shadow-xl" alt="avatar" />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && (
            <Transactions 
              transactions={transactions} 
              potes={potes} 
              onAdd={handleAddTransaction} 
              onDelete={handleDeleteTransaction}
              onEdit={handleEditTransaction}
            />
          )}
          {view === 'budgets' && <Budgets budgets={budgets} onUpdate={(b) => setBudgets(budgets.map(item => item.category === b.category ? b : item))} />}
          {view === 'goals' && <Goals goals={goals} onAdd={(g) => setGoals([...goals, g])} />}
          {view === 'potes' && <Potes potes={potes} onUpdate={setPotes} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  Target, 
  Wallet, 
  BrainCircuit, 
  Plus, 
  Menu,
  X,
  Archive
} from 'lucide-react';
import { AppView, Transaction, Budget, FinancialGoal, Jar } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Necessidades Básicas', percentage: 50, balance: 2500 },
  { id: '2', name: 'Investimentos', percentage: 30, balance: 1500 },
  { id: '3', name: 'Lazer', percentage: 20, balance: 1000 },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : [
      { id: '1', description: 'Salário Mensal', amount: 5000, category: 'Salário', date: new Date().toISOString().split('T')[0], type: 'income' },
      { id: '2', description: 'Aluguel', amount: 1500, category: 'Moradia', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1' },
    ];
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [budgets, setBudgets] = useState<Budget[]>(() => {
    const saved = localStorage.getItem('zen_budgets');
    return saved ? JSON.parse(saved) : [
      { category: 'Moradia', limit: 1600, spent: 1500 },
      { category: 'Alimentação', limit: 800, spent: 0 },
    ];
  });

  const [goals, setGoals] = useState<FinancialGoal[]>(() => {
    const saved = localStorage.getItem('zen_goals');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Reserva de Emergência', targetAmount: 15000, currentAmount: 3000, deadline: '2024-12-31' },
    ];
  });

  // Salva no LocalStorage sempre que houver mudanças nos estados principais
  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [transactions, potes, budgets, goals]);

  const financialData = useMemo(() => ({ transactions, budgets, goals, potes }), [transactions, budgets, goals, potes]);

  /**
   * Lógica centralizada para atualização de saldos nos potes.
   * @param t Transação a ser processada
   * @param currentJars Lista atual de potes
   * @param isRemoval Se verdadeiro, reverte o impacto financeiro (ex: ao excluir uma transação)
   */
  const calculatePotesUpdate = (t: Transaction, currentJars: Jar[], isRemoval: boolean = false) => {
    const multiplier = isRemoval ? -1 : 1;

    return currentJars.map(pote => {
      if (t.type === 'income') {
        // Entradas: Distribuídas entre todos os potes com base na porcentagem de cada um
        const share = t.amount * (pote.percentage / 100);
        return { ...pote, balance: pote.balance + (share * multiplier) };
      } else if (t.type === 'expense' && t.poteId === pote.id) {
        // Saídas: Deduzidas INTEGRALMENTE de um pote específico selecionado pelo usuário
        return { ...pote, balance: pote.balance - (t.amount * multiplier) };
      }
      return pote;
    });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions(prev => [t, ...prev]);
    setPotes(prev => calculatePotesUpdate(t, prev, false));
  };

  const handleDeleteTransaction = (id: string) => {
    // Localiza a transação antes de deletar para poder reverter o saldo
    const txToDelete = transactions.find(t => t.id === id);
    if (!txToDelete) return;

    if (window.confirm('Excluir esta transação? Os saldos do sistema e dos potes serão automaticamente ajustados.')) {
      // Importante: a ordem aqui importa para não usar estado obsoleto
      setTransactions(prev => prev.filter(t => t.id !== id));
      setPotes(prev => calculatePotesUpdate(txToDelete, prev, true));
    }
  };

  const handleEditTransaction = (updatedTx: Transaction) => {
    const oldTx = transactions.find(t => t.id === updatedTx.id);
    if (!oldTx) return;

    setTransactions(prev => prev.map(t => t.id === updatedTx.id ? updatedTx : t));

    setPotes(prev => {
      // 1. Primeiro remove o impacto da transação antiga
      const reverted = calculatePotesUpdate(oldTx, prev, true);
      // 2. Depois aplica o impacto da transação com os novos valores
      return calculatePotesUpdate(updatedTx, reverted, false);
    });
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'potes', label: 'Potes', icon: Archive },
    { id: 'transactions', label: 'Transações', icon: Receipt },
    { id: 'budgets', label: 'Orçamentos', icon: Wallet },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100">
      <aside className={`fixed md:sticky top-0 h-screen z-30 transition-all duration-300 ${isSidebarOpen ? 'w-56 translate-x-0' : 'w-0 -translate-x-full md:w-16 md:translate-x-0'} bg-[#0a0c14] border-r border-slate-800 flex flex-col overflow-hidden`}>
        <div className="p-5 flex items-center gap-2">
          <div className="bg-indigo-500/10 p-2 rounded-xl border border-indigo-500/20"><BrainCircuit className="w-5 h-5 text-indigo-400" /></div>
          {isSidebarOpen && <span className="text-lg font-bold tracking-tighter text-white">ZenFinance</span>}
        </div>
        <nav className="flex-1 px-2 mt-4 space-y-1">
          {navItems.map((item) => (
            <button key={item.id} onClick={() => setView(item.id as AppView)} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${view === item.id ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/20' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800/40'}`}>
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {isSidebarOpen && <span className="font-semibold text-sm">{item.label}</span>}
            </button>
          ))}
        </nav>
        <div className="p-3 border-t border-slate-800">
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-full flex items-center justify-center p-2 rounded-lg hover:bg-slate-800 transition-colors">
            {isSidebarOpen ? <X className="w-4 h-4 text-slate-500" /> : <Menu className="w-4 h-4 text-slate-500" />}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        <header className="h-14 glass sticky top-0 z-10 px-5 flex items-center justify-between">
          <h1 className="text-lg font-bold text-white capitalize tracking-tight">{navItems.find(i => i.id === view)?.label}</h1>
          <div className="flex items-center gap-3">
             <div className="flex items-center gap-2 bg-slate-800/40 px-3 py-1 rounded-full border border-slate-700/50">
                <div className="w-2 h-2 bg-indigo-500 rounded-full animate-pulse"></div>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Premium AI</span>
             </div>
             <img src="https://picsum.photos/seed/finance/32/32" className="w-8 h-8 rounded-full border-2 border-slate-700 shadow-xl" alt="avatar" />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && (
            <Transactions 
              transactions={transactions} 
              potes={potes} 
              onAdd={handleAddTransaction} 
              onDelete={handleDeleteTransaction}
              onEdit={handleEditTransaction}
            />
          )}
          {view === 'budgets' && <Budgets budgets={budgets} onUpdate={(b) => setBudgets(budgets.map(item => item.category === b.category ? b : item))} />}
          {view === 'goals' && <Goals goals={goals} onAdd={(g) => setGoals([...goals, g])} />}
          {view === 'potes' && <Potes potes={potes} onUpdate={setPotes} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

import React from 'react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend
} from 'recharts';
import { TrendingUp, TrendingDown, Wallet } from 'lucide-react';
import { FinancialData } from '../types';

interface DashboardProps {
  data: FinancialData;
}

export default function Dashboard({ data }: DashboardProps) {
  const { transactions, potes } = data;

  // Cálculo de Saldo Total (Todo o histórico)
  const totalIncome = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
  const totalExpense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
  const totalBalance = totalIncome - totalExpense;

  // Estatísticas Mensais (Filtro do primeiro ao último dia do mês atual)
  const now = new Date();
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const endOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);

  const monthTransactions = transactions.filter(t => {
    const d = new Date(t.date);
    return d >= startOfMonth && d <= endOfMonth;
  });

  const monthIncome = monthTransactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
  const monthExpense = monthTransactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);

  const chartData = transactions.slice(-10).reverse().map(t => ({
    name: t.date.split('-').reverse().slice(0, 2).join('/'),
    amount: t.type === 'income' ? t.amount : -t.amount,
  }));

  const pieData = potes.map(p => ({
    name: p.name,
    value: p.balance > 0 ? p.balance : 0
  })).filter(p => p.value > 0);

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316', '#eab308'];

  return (
    <div className="space-y-6">
      {/* Seção Principal: Barras de Resumo */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
        {/* Card Saldo Total */}
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-900 p-6 rounded-3xl shadow-2xl border border-white/5 relative overflow-hidden group">
          <div className="absolute -right-4 -top-4 w-24 h-24 bg-white/5 rounded-full blur-2xl"></div>
          <div className="flex items-center gap-3 mb-3 relative z-10">
            <div className="bg-white/10 p-2.5 rounded-xl border border-white/10">
              <Wallet className="w-5 h-5 text-white" />
            </div>
            <span className="text-indigo-100/70 text-[10px] font-black uppercase tracking-[0.15em]">Saldo Total Acumulado</span>
          </div>
          <p className="text-3xl font-bold text-white tracking-tighter relative z-10">
            R$ {totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </p>
        </div>

        {/* Card Entradas do Mês */}
        <div className="bg-[#111827]/60 backdrop-blur-xl p-6 rounded-3xl border border-white/5 hover:border-emerald-500/20 transition-all group">
          <div className="flex items-center gap-3 mb-3">
            <div className="bg-emerald-500/10 p-2.5 rounded-xl border border-emerald-500/20 group-hover:bg-emerald-500/20">
              <TrendingUp className="w-5 h-5 text-emerald-400" />
            </div>
            <span className="text-slate-400 text-[10px] font-black uppercase tracking-[0.15em]">Entradas (Este Mês)</span>
          </div>
          <p className="text-3xl font-bold text-emerald-400 tracking-tighter">
            R$ {monthIncome.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </p>
          <div className="mt-4 w-full bg-slate-800/50 h-1.5 rounded-full overflow-hidden">
            <div className="h-full bg-emerald-500 w-full opacity-30 shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
          </div>
        </div>

        {/* Card Saídas do Mês */}
        <div className="bg-[#111827]/60 backdrop-blur-xl p-6 rounded-3xl border border-white/5 hover:border-rose-500/20 transition-all group">
          <div className="flex items-center gap-3 mb-3">
            <div className="bg-rose-500/10 p-2.5 rounded-xl border border-rose-500/20 group-hover:bg-rose-500/20">
              <TrendingDown className="w-5 h-5 text-rose-400" />
            </div>
            <span className="text-slate-400 text-[10px] font-black uppercase tracking-[0.15em]">Saídas (Este Mês)</span>
          </div>
          <p className="text-3xl font-bold text-rose-400 tracking-tighter">
            R$ {monthExpense.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </p>
          <div className="mt-4 w-full bg-slate-800/50 h-1.5 rounded-full overflow-hidden">
             {/* Simulação de barra de gasto relativo à entrada se houver entrada */}
             <div 
               className="h-full bg-rose-500 transition-all duration-1000 shadow-[0_0_8px_rgba(244,63,94,0.5)]" 
               style={{ width: `${Math.min((monthExpense / (monthIncome || 1)) * 100, 100)}%` }} 
             />
          </div>
        </div>
      </div>

      {/* Grid de Potes - Atualizados conforme Entradas/Saídas */}
      <div className="space-y-4 pt-4">
        <div className="flex items-center justify-between">
            <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                Arquitetura de Potes
            </h3>
            <span className="text-[10px] text-slate-600 font-bold uppercase">Sincronizado com Saldo Total</span>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {potes.map((pote, idx) => (
            <div key={pote.id} className="bg-[#0f172a]/80 p-5 rounded-2xl border border-white/5 hover:border-indigo-500/30 transition-all shadow-xl group">
              <div className="flex justify-between items-center mb-3">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest group-hover:text-indigo-400">{pote.name}</span>
                <span className="text-[9px] font-black text-indigo-400 bg-indigo-400/10 px-2 py-0.5 rounded-full border border-indigo-400/20">{pote.percentage}%</span>
              </div>
              <p className={`text-2xl font-bold tracking-tighter ${pote.balance < 0 ? 'text-rose-500' : 'text-slate-100'}`}>
                R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </p>
              <div className="mt-4 w-full bg-slate-800 h-1.5 rounded-full overflow-hidden border border-white/5">
                <div 
                  className="h-full transition-all duration-1000 shadow-[0_0_8px_rgba(99,102,241,0.5)]" 
                  style={{ width: `${pote.percentage}%`, backgroundColor: COLORS[idx % COLORS.length] }} 
                />
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Gráficos de Apoio */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-[#111827]/60 backdrop-blur-md p-6 rounded-3xl border border-white/5">
          <h3 className="text-sm font-bold text-slate-400 mb-6 flex items-center gap-2">Alocação de Capital (Potes)</h3>
          <div className="h-[250px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={pieData} cx="50%" cy="50%" innerRadius={60} outerRadius={90} paddingAngle={8} dataKey="value">
                  {pieData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="rgba(0,0,0,0.1)" strokeWidth={2} />)}
                </Pie>
                <Tooltip 
                   contentStyle={{backgroundColor: '#1e293b', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.1)', fontSize: '11px', color: '#fff'}}
                   itemStyle={{color: '#fff'}}
                />
                <Legend iconType="circle" wrapperStyle={{fontSize: '11px', color: '#94a3b8'}} layout="vertical" align="right" verticalAlign="middle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-[#111827]/60 backdrop-blur-md p-6 rounded-3xl border border-white/5">
          <h3 className="text-sm font-bold text-slate-400 mb-6 uppercase tracking-widest text-[10px]">Movimentação Recente</h3>
          <div className="h-[250px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorAmt" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#6366f1" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10}} />
                <Tooltip contentStyle={{backgroundColor: '#1e293b', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.1)', fontSize: '11px'}} />
                <Area type="monotone" dataKey="amount" stroke="#6366f1" strokeWidth={3} fillOpacity={1} fill="url(#colorAmt)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
}

