export type TransactionType = 'income' | 'expense';

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  category: string;
  date: string;
  type: TransactionType;
  poteId?: string; // Obrigatório para despesas
  paymentMethod?: string;
  isRecurring?: boolean;
}

export interface Debt {
  id: string;
  name: string;
  totalAmount: number;
  remainingAmount: number;
  dueDate: string;
  category: string;
  interestRate?: number;
  status: 'active' | 'paid' | 'overdue';
}

export interface Jar {
  id: string;
  name: string;
  percentage: number;
  balance: number;
}

export interface Budget {
  category: string;
  limit: number;
  spent: number;
}

export interface FinancialGoal {
  id: string;
  name: string;
  targetAmount: number;
  currentAmount: number;
  deadline: string;
}

export interface FinancialData {
  transactions: Transaction[];
  budgets: Budget[];
  goals: FinancialGoal[];
  potes: Jar[];
  debts: Debt[];
}

export type AppView = 'dashboard' | 'transactions' | 'budgets' | 'goals' | 'potes' | 'advisor' | 'debts';

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  Target, 
  Wallet, 
  BrainCircuit, 
  Plus, 
  Menu,
  X,
  Archive,
  AlertCircle
} from 'lucide-react';
import { AppView, Transaction, Budget, FinancialGoal, Jar, Debt } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Debts from './components/Debts';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Necessidades Básicas', percentage: 50, balance: 2500 },
  { id: '2', name: 'Investimentos', percentage: 30, balance: 1500 },
  { id: '3', name: 'Lazer', percentage: 20, balance: 1000 },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => {
    const saved = localStorage.getItem('zen_debts');
    return saved ? JSON.parse(saved) : [
      { id: 'd1', name: 'Financiamento Carro', totalAmount: 45000, remainingAmount: 12000, dueDate: '2024-05-15', category: 'Veículo', status: 'active' }
    ];
  });

  const [budgets, setBudgets] = useState<Budget[]>(() => {
    const saved = localStorage.getItem('zen_budgets');
    return saved ? JSON.parse(saved) : [];
  });

  const [goals, setGoals] = useState<FinancialGoal[]>(() => {
    const saved = localStorage.getItem('zen_goals');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
  }, [transactions, potes, budgets, goals, debts]);

  const calculatePotesUpdate = (t: Transaction, currentJars: Jar[], isRemoval: boolean = false) => {
    const multiplier = isRemoval ? -1 : 1;
    return currentJars.map(pote => {
      if (t.type === 'income') {
        const share = t.amount * (pote.percentage / 100);
        return { ...pote, balance: pote.balance + (share * multiplier) };
      } else if (t.type === 'expense' && t.poteId === pote.id) {
        return { ...pote, balance: pote.balance - (t.amount * multiplier) };
      }
      return pote;
    });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions(prev => [t, ...prev]);
    setPotes(prev => calculatePotesUpdate(t, prev, false));
  };

  const handleDeleteTransaction = (id: string) => {
    const txToDelete = transactions.find(t => t.id === id);
    if (!txToDelete && !window.confirm('Excluir transação?')) return;
    if (txToDelete) {
      setTransactions(prev => prev.filter(t => t.id !== id));
      setPotes(prev => calculatePotesUpdate(txToDelete, prev, true));
    }
  };

  const handleEditTransaction = (updatedTx: Transaction) => {
    const oldTx = transactions.find(t => t.id === updatedTx.id);
    if (!oldTx) return;
    setTransactions(prev => prev.map(t => t.id === updatedTx.id ? updatedTx : t));
    setPotes(prev => {
      const reverted = calculatePotesUpdate(oldTx, prev, true);
      return calculatePotesUpdate(updatedTx, reverted, false);
    });
  };

  const financialData = useMemo(() => ({ transactions, budgets, goals, potes, debts }), [transactions, budgets, goals, potes, debts]);

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'Despesas/Fluxo', icon: Receipt },
    { id: 'debts', label: 'Dívidas/Contas', icon: AlertCircle },
    { id: 'potes', label: 'Potes AI', icon: Archive },
    { id: 'budgets', label: 'Orçamentos', icon: Wallet },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'advisor', label: 'ZenAdvisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100 font-sans">
      <aside className={`fixed md:sticky top-0 h-screen z-30 transition-all duration-300 ${isSidebarOpen ? 'w-60 translate-x-0' : 'w-0 -translate-x-full md:w-20 md:translate-x-0'} bg-[#0a0c14] border-r border-slate-800 flex flex-col overflow-hidden`}>
        <div className="p-6 flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl"><BrainCircuit className="w-6 h-6 text-white" /></div>
          {isSidebarOpen && <span className="text-xl font-bold tracking-tight text-white">ZenFinance</span>}
        </div>
        <nav className="flex-1 px-3 mt-4 space-y-2">
          {navItems.map((item) => (
            <button key={item.id} onClick={() => setView(item.id as AppView)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl transition-all ${view === item.id ? 'bg-indigo-600/10 text-indigo-400 border border-indigo-500/20' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800/40'}`}>
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {isSidebarOpen && <span className="font-bold text-sm tracking-wide">{item.label}</span>}
            </button>
          ))}
        </nav>
        <div className="p-4 border-t border-slate-800">
           <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-full flex items-center justify-center p-2 rounded-xl hover:bg-slate-800 transition-colors">
            {isSidebarOpen ? <X className="w-4 h-4 text-slate-600" /> : <Menu className="w-4 h-4 text-slate-600" />}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        <header className="h-16 glass sticky top-0 z-10 px-6 flex items-center justify-between">
          <h1 className="text-xl font-black text-white uppercase tracking-widest">{navItems.find(i => i.id === view)?.label}</h1>
          <div className="flex items-center gap-4">
             <div className="hidden md:flex flex-col text-right">
                <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Sincronização Ativa</span>
                <span className="text-[11px] text-emerald-400 font-bold">Cloud Zen Secure</span>
             </div>
             <img src="https://picsum.photos/seed/finance_zen/40/40" className="w-10 h-10 rounded-2xl border-2 border-slate-800 shadow-2xl" alt="avatar" />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && (
            <Transactions 
              transactions={transactions} 
              potes={potes} 
              onAdd={handleAddTransaction} 
              onDelete={handleDeleteTransaction}
              onEdit={handleEditTransaction}
            />
          )}
          {view === 'debts' && (
             <Debts 
                debts={debts} 
                potes={potes}
                onAdd={(d) => setDebts([...debts, d])}
                onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))}
                onPay={(d, amount, poteId) => {
                   // Atualiza a dívida
                   const updatedDebt = { ...d, remainingAmount: d.remainingAmount - amount };
                   if (updatedDebt.remainingAmount <= 0) updatedDebt.status = 'paid' as any;
                   setDebts(debts.map(item => item.id === d.id ? updatedDebt : item));

                   // Gera a transação de pagamento
                   handleAddTransaction({
                      id: Math.random().toString(36).substr(2, 9),
                      description: `Pgmto Dívida: ${d.name}`,
                      amount: amount,
                      category: 'Dívidas',
                      date: new Date().toISOString().split('T')[0],
                      type: 'expense',
                      poteId: poteId
                   });
                }}
             />
          )}
          {view === 'budgets' && <Budgets budgets={budgets} onUpdate={(b) => setBudgets(budgets.map(item => item.category === b.category ? b : item))} />}
          {view === 'goals' && <Goals goals={goals} onAdd={(g) => setGoals([...goals, g])} />}
          {view === 'potes' && <Potes potes={potes} onUpdate={setPotes} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Debt, Jar } from '../types';
import { Plus, CheckCircle2, AlertTriangle, Calendar, CreditCard, ChevronRight, DollarSign, X } from 'lucide-react';

interface DebtsProps {
  debts: Debt[];
  potes: Jar[];
  onAdd: (d: Debt) => void;
  onUpdate: (d: Debt) => void;
  onPay: (d: Debt, amount: number, poteId: string) => void;
