export default function Debts({ debts, potes, onAdd, onUpdate, onPay }: DebtsProps) {
  const [showAddModal, setShowAddModal] = useState(false);
  const [paymentModal, setPaymentModal] = useState<{ debt: Debt | null, amount: number, poteId: string }>({ debt: null, amount: 0, poteId: potes[0]?.id || '' });

