                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-4">
                    <div className={`p-3 rounded-2xl ${debt.status === 'paid' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                      {debt.status === 'paid' ? <CheckCircle2 /> : <AlertTriangle />}
                    </div>
                    <div>
                      <h4 className="font-bold text-white text-lg tracking-tight">{debt.name}</h4>
                      <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">{debt.category}</span>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mb-1">Vencimento</p>
                    <div className="flex items-center gap-2 text-slate-200 text-sm font-bold">
                      <Calendar className="w-4 h-4 text-indigo-400" />
                      {new Date(debt.dueDate).toLocaleDateString('pt-BR')}
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4 mb-6">
                    <div className="bg-slate-900/40 p-3 rounded-2xl border border-white/5">
