                  type="number" 
                  className="w-full px-4 py-3 bg-slate-900/50 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  placeholder="R$ 0,00"
                  onChange={(e) => setPaymentModal({ ...paymentModal, amount: parseFloat(e.target.value) })}
                />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-2">Pote de Origem</label>
                <select 
                  className="w-full px-4 py-3 bg-slate-900/50 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.poteId}
                  onChange={(e) => setPaymentModal({ ...paymentModal, poteId: e.target.value })}
                >
                  {potes.map(p => <option key={p.id} value={p.id}>{p.name} (R$ {p.balance.toLocaleString()})</option>)}
                </select>
              </div>
              <button 
                onClick={() => {
                  if (paymentModal.debt && paymentModal.amount > 0) {
                    onPay(paymentModal.debt, paymentModal.amount, paymentModal.poteId);
                    setPaymentModal({ debt: null, amount: 0, poteId: '' });
                  }
                }}
                className="w-full py-4 bg-emerald-500 text-emerald-950 font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-emerald-400 transition-all shadow-xl shadow-emerald-500/20"
              >
                Confirmar Pagamento
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { Search, Plus, Minus, ArrowUpCircle, ArrowDownCircle, X, Trash2, Edit2, Check, CreditCard, Tag } from 'lucide-react';
import { Transaction, TransactionType, Jar } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
}

export default function Transactions({ transactions, potes, onAdd, onDelete, onEdit }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '', amount: 0, category: 'Geral', type: 'expense', date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : '', paymentMethod: 'PIX', isRecurring: false
  });

  const filteredTransactions = transactions.filter(t => {
    const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          t.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = typeFilter === 'all' || t.type === typeFilter;
    return matchesSearch && matchesType;
  });

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '', amount: 0, category: type === 'income' ? 'Salário' : 'Consumo', type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : undefined,
      paymentMethod: 'PIX', isRecurring: false
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount) return;
    if (currentTx.type === 'expense' && !currentTx.poteId) {
       alert("Selecione um pote de origem para esta despesa.");
       return;
    }

    if (modalType === 'add') {
      onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    } else if (modalType === 'edit') {
      onEdit(currentTx as Transaction);
    }
    setModalType(null);
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <button 
          onClick={() => handleOpenAdd('income')}
          className="group relative flex items-center justify-center gap-3 py-5 bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 rounded-3xl hover:bg-emerald-500/20 transition-all font-black uppercase text-xs tracking-widest shadow-xl shadow-emerald-500/5"
        >
