export type TransactionType = 'income' | 'expense';

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  category: string;
  date: string;
  type: TransactionType;
  poteId?: string;
  paymentMethod?: string;
  isRecurring?: boolean;
}

export interface Task {
  id: string;
  title: string;
  completed: boolean;
  priority: 'low' | 'medium' | 'high';
  dueDate: string;
  tags: string[];
}

export interface Note {
  id: string;
  title: string;
  content: string;
  date: string;
  tags: string[];
}

export interface JournalEntry {
  id: string;
  content: string;
  mood: string;
  date: string;
}

export interface CalendarEvent {
  id: string;
  title: string;
  startTime: string;
  endTime: string;
  location?: string;
}

export interface Debt {
  id: string;
  name: string;
  totalAmount: number;
  remainingAmount: number;
  dueDate: string;
  category: string;
  status: 'active' | 'paid' | 'overdue';
}

export interface Jar {
  id: string;
  name: string;
  percentage: number;
  balance: number;
}

export interface Budget {
  category: string;
  limit: number;
  spent: number;
}

export interface FinancialGoal {
  id: string;
  name: string;
  targetAmount: number;
  currentAmount: number;
  deadline: string;
}

export interface FinancialData {
  transactions: Transaction[];
  budgets: Budget[];
  goals: FinancialGoal[];
  potes: Jar[];
  debts: Debt[];
  tasks: Task[];
  notes: Note[];
  journal: JournalEntry[];
  events: CalendarEvent[];
}

