import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, Receipt, Target, Wallet, BrainCircuit, Menu, X, Archive, 
  AlertCircle, CheckSquare, FileText, BookOpen, Calendar as CalendarIcon
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Task, Note, JournalEntry, CalendarEvent, Budget, FinancialGoal } from './types';
import Dashboard from './components/Dashboard';
