const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Necessidades Básicas', percentage: 50, balance: 2500 },
  { id: '2', name: 'Investimentos', percentage: 30, balance: 1500 },
  { id: '3', name: 'Lazer', percentage: 20, balance: 1000 },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Estados dos Módulos
  const [transactions, setTransactions] = useState<Transaction[]>(() => JSON.parse(localStorage.getItem('zen_transactions') || '[]'));
  const [potes, setPotes] = useState<Jar[]>(() => JSON.parse(localStorage.getItem('zen_potes') || JSON.stringify(INITIAL_POTES)));
  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [tasks, setTasks] = useState<Task[]>(() => JSON.parse(localStorage.getItem('zen_tasks') || '[]'));
  const [notes, setNotes] = useState<Note[]>(() => JSON.parse(localStorage.getItem('zen_notes') || '[]'));
  const [journal, setJournal] = useState<JournalEntry[]>(() => JSON.parse(localStorage.getItem('zen_journal') || '[]'));
  const [events, setEvents] = useState<CalendarEvent[]>(() => JSON.parse(localStorage.getItem('zen_events') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_tasks', JSON.stringify(tasks));
    localStorage.setItem('zen_notes', JSON.stringify(notes));
    localStorage.setItem('zen_journal', JSON.stringify(journal));
    localStorage.setItem('zen_events', JSON.stringify(events));
  }, [transactions, potes, debts, tasks, notes, journal, events]);

  const financialData = useMemo(() => ({ 
    transactions, potes, debts, tasks, notes, journal, events,
    budgets: [], goals: [] // Simplificado para o exemplo
  }), [transactions, potes, debts, tasks, notes, journal, events]);

  const calculatePotesUpdate = (t: Transaction, currentJars: Jar[], isRemoval: boolean = false) => {
    const multiplier = isRemoval ? -1 : 1;
    return currentJars.map(pote => {
      if (t.type === 'income') {
        const share = t.amount * (pote.percentage / 100);
        return { ...pote, balance: pote.balance + (share * multiplier) };
      } else if (t.type === 'expense' && t.poteId === pote.id) {
        return { ...pote, balance: pote.balance - (t.amount * multiplier) };
      }
      return pote;
    });
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard },
    { id: 'transactions', label: 'Finanças', icon: Receipt },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle },
    { id: 'tasks', label: 'Tarefas', icon: CheckSquare },
    { id: 'calendar', label: 'Agenda', icon: CalendarIcon },
    { id: 'notes', label: 'Notas', icon: FileText },
    { id: 'journal', label: 'Diário', icon: BookOpen },
    { id: 'potes', label: 'Potes', icon: Archive },
    { id: 'advisor', label: 'ZenAdvisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100 font-sans overflow-hidden">
      {/* Sidebar ZenOS */}
      <aside className={`fixed md:sticky top-0 h-screen z-30 transition-all duration-300 ${isSidebarOpen ? 'w-64 translate-x-0' : 'w-0 -translate-x-full md:w-20 md:translate-x-0'} bg-[#0a0c14] border-r border-slate-800 flex flex-col`}>
        <div className="p-6 flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
          {isSidebarOpen && <span className="text-xl font-bold tracking-tight text-white">ZenOS</span>}
        </div>
        <nav className="flex-1 px-3 mt-4 space-y-1 overflow-y-auto">
          {navItems.map((item) => (
            <button key={item.id} onClick={() => setView(item.id as AppView)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl transition-all ${view === item.id ? 'bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 shadow-[0_0_15px_rgba(79,70,229,0.1)]' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800/40'}`}>
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {isSidebarOpen && <span className="font-bold text-sm tracking-wide">{item.label}</span>}
            </button>
          ))}
        </nav>
        <div className="p-4 border-t border-slate-800">
           <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-full flex items-center justify-center p-2.5 rounded-xl hover:bg-slate-800 transition-colors">
            {isSidebarOpen ? <X className="w-4 h-4 text-slate-600" /> : <Menu className="w-4 h-4 text-slate-600" />}
          </button>
        </div>
      </aside>

      {/* Main Context */}
      <main className="flex-1 flex flex-col min-w-0 h-screen">
        <header className="h-16 glass sticky top-0 z-10 px-8 flex items-center justify-between">
          <h1 className="text-xl font-black text-white uppercase tracking-widest">{navItems.find(i => i.id === view)?.label}</h1>
          <div className="flex items-center gap-4">
             <div className="hidden md:flex flex-col text-right">
                <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Master Assistant</span>
                <span className="text-[11px] text-indigo-400 font-bold">Sync: 100% Stable</span>
             </div>
             <div className="w-10 h-10 rounded-2xl bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <BrainCircuit className="w-5 h-5 text-indigo-400" />
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 pb-12">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && (
            <Transactions 
              transactions={transactions} potes={potes} 
              onAdd={(t) => { setTransactions([t, ...transactions]); setPotes(prev => calculatePotesUpdate(t, prev)); }} 
              onDelete={(id) => { const tx = transactions.find(t => t.id === id); if(tx) { setTransactions(transactions.filter(t => t.id !== id)); setPotes(prev => calculatePotesUpdate(tx, prev, true)); } }}
              onEdit={(t) => { /* logic here */ }}
            />
          )}
          {view === 'debts' && (
            <Debts 
              debts={debts} potes={potes}
              onAdd={(d) => setDebts([...debts, d])}
              onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))}
              onPay={(d, amt, pId) => { /* logic from previous implementation */ }}
            />
          )}
          {view === 'tasks' && <Tasks tasks={tasks} onUpdate={setTasks} />}
          {view === 'notes' && <Notes notes={notes} onUpdate={setNotes} />}
          {view === 'journal' && <Journal journal={journal} onUpdate={setJournal} />}
          {view === 'potes' && <Potes potes={potes} onUpdate={setPotes} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Task } from '../types';
import { Plus, CheckCircle, Circle, Trash2, Calendar, Tag, Flag } from 'lucide-react';

interface TasksProps {
  tasks: Task[];
  onUpdate: (tasks: Task[]) => void;
}

export default function Tasks({ tasks, onUpdate }: TasksProps) {
  const [newTitle, setNewTitle] = useState('');
  const [priority, setPriority] = useState<Task['priority']>('medium');

  const addTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTitle.trim()) return;
    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      completed: false,
      priority,
      dueDate: new Date().toISOString().split('T')[0],
      tags: []
    };
    onUpdate([newTask, ...tasks]);
    setNewTitle('');
  };

  const toggleTask = (id: string) => {
    onUpdate(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const deleteTask = (id: string) => {
    onUpdate(tasks.filter(t => t.id !== id));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <form onSubmit={addTask} className="bg-[#111827]/60 p-6 rounded-[2.5rem] border border-white/5 flex flex-col md:flex-row gap-4 items-center">
        <input 
          type="text" 
          placeholder="O que precisa ser feito?" 
          className="flex-1 bg-transparent border-none text-white text-lg outline-none placeholder:text-slate-600 px-4"
          value={newTitle}
          onChange={(e) => setNewTitle(e.target.value)}
        />
        <div className="flex gap-2">
          {['low', 'medium', 'high'].map((p) => (
            <button 
              key={p} type="button" 
              onClick={() => setPriority(p as any)}
              className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${priority === p ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}
            >
              {p}
            </button>
          ))}
          <button type="submit" className="bg-white text-slate-950 px-6 py-2 rounded-xl font-black uppercase text-xs tracking-widest hover:bg-indigo-400 hover:text-white transition-all">
            Adicionar
          </button>
        </div>
      </form>

      <div className="space-y-4">
        {tasks.map(task => (
          <div key={task.id} className={`group flex items-center justify-between p-5 rounded-[1.5rem] border transition-all ${task.completed ? 'bg-slate-900/20 border-white/5 opacity-50' : 'bg-[#111827]/60 border-white/10 hover:border-indigo-500/30'}`}>
            <div className="flex items-center gap-4">
              <button onClick={() => toggleTask(task.id)} className="transition-transform active:scale-90">
                {task.completed ? <CheckCircle className="w-6 h-6 text-emerald-500" /> : <Circle className="w-6 h-6 text-slate-600 group-hover:text-indigo-500" />}
              </button>
              <div>
                <p className={`font-bold text-sm ${task.completed ? 'line-through text-slate-600' : 'text-slate-200'}`}>{task.title}</p>
                <div className="flex gap-3 mt-1">
                  <span className={`text-[9px] font-black uppercase tracking-widest ${task.priority === 'high' ? 'text-rose-400' : task.priority === 'medium' ? 'text-indigo-400' : 'text-slate-500'}`}>
                    <Flag className="w-2.5 h-2.5 inline mr-1" /> {task.priority}
                  </span>
                  <span className="text-[9px] font-black uppercase tracking-widest text-slate-600">
                    <Calendar className="w-2.5 h-2.5 inline mr-1" /> {new Date(task.dueDate).toLocaleDateString()}
                  </span>
                </div>
              </div>
