            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-white uppercase tracking-tighter">Criar Nota</h3>
              <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-white/5 rounded-full"><X className="w-6 h-6 text-slate-500" /></button>
            </div>
            <div className="space-y-6">
              <input 
                placeholder="Título da nota" 
                className="w-full bg-slate-900 border border-slate-700 px-5 py-4 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500"
                value={newNote.title}
                onChange={e => setNewNote({...newNote, title: e.target.value})}
              />
              <textarea 
                placeholder="Conteúdo..." 
                className="w-full h-48 bg-slate-900 border border-slate-700 px-5 py-4 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500 resize-none"
