import { GoogleGenAI } from "@google/genai";
import { FinancialData } from "../types";

export const getFinancialAdvice = async (data: FinancialData, userQuery: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const contextSummary = {
    balance: data.transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0) - 
             data.transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0),
    pendingTasks: data.tasks.filter(t => !t.completed).length,
    latestMood: data.journal[0]?.mood || 'N/A',
    notesCount: data.notes.length
  };

  const systemInstruction = `
    Você é o ZenOS Master Assistant, um sistema operacional pessoal e financeiro inteligente.
    Seu objetivo é ser o único ponto de contato para a vida produtiva, emocional e financeira do usuário.
    Analise os dados unificados e responda de forma executiva, clara e proativa.

    Estado Atual do Usuário:
    - Saldo Financeiro: R$ ${contextSummary.balance}
    - Tarefas Pendentes: ${contextSummary.pendingTasks}
    - Último Estado Emocional: ${contextSummary.latestMood}
    - Conhecimento Acumulado (Notas): ${contextSummary.notesCount}

    Capacidades:
    1. Interpretar gastos ("Gastei 50 no mercado").
    2. Organizar tarefas ("Lembre-me de pagar o aluguel").
    3. Resumir estados emocionais baseados no diário.
    4. Conectar ideias registradas em notas com metas financeiras.

    Regras:
    - Use Markdown.
    - Seja empático mas focado em resultados.
    - Responda em Português (Brasil).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userQuery,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.7,
      },
    });

    return response.text;
  } catch (error) {
    console.error("ZenOS AI Error:", error);
    return "Desculpe, meu processamento neural falhou. Tente novamente em breve.";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, Receipt, Target, Wallet, BrainCircuit, Menu, X, Archive, 
  AlertCircle, CheckSquare, FileText, BookOpen, Calendar as CalendarIcon
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Task, Note, JournalEntry, CalendarEvent } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Tasks from './components/Tasks';
import Notes from './components/Notes';
import Journal from './components/Journal';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Reserva/Poupança', percentage: 20, balance: 0 },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Estados dos Módulos
  const [transactions, setTransactions] = useState<Transaction[]>(() => JSON.parse(localStorage.getItem('zen_transactions') || '[]'));
  const [potes, setPotes] = useState<Jar[]>(() => JSON.parse(localStorage.getItem('zen_potes') || JSON.stringify(INITIAL_POTES)));
  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [tasks, setTasks] = useState<Task[]>(() => JSON.parse(localStorage.getItem('zen_tasks') || '[]'));
  const [notes, setNotes] = useState<Note[]>(() => JSON.parse(localStorage.getItem('zen_notes') || '[]'));
  const [journal, setJournal] = useState<JournalEntry[]>(() => JSON.parse(localStorage.getItem('zen_journal') || '[]'));
  const [events, setEvents] = useState<CalendarEvent[]>(() => JSON.parse(localStorage.getItem('zen_events') || '[]'));

  // Persistência
  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_tasks', JSON.stringify(tasks));
    localStorage.setItem('zen_notes', JSON.stringify(notes));
    localStorage.setItem('zen_journal', JSON.stringify(journal));
    localStorage.setItem('zen_events', JSON.stringify(events));
  }, [transactions, potes, debts, tasks, notes, journal, events]);

  /**
   * MOTOR FINANCEIRO CENTRAL (Derived State)
   * Recalcula os saldos de cada pote toda vez que transações ou configurações de potes mudam.
   */
  const processedPotes = useMemo(() => {
    return potes.map(pote => {
      let balance = 0;
      transactions.forEach(t => {
        if (t.type === 'income') {
          // Distribuição automática baseada na porcentagem atual do pote
          balance += t.amount * (pote.percentage / 100);
        } else if (t.type === 'expense' && t.poteId === pote.id) {
          // Débito direto do pote selecionado
          balance -= t.amount;
        }
      });
      return { ...pote, balance };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, tasks, notes, journal, events,
    budgets: [], goals: [] 
  }), [transactions, processedPotes, debts, tasks, notes, journal, events]);

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard },
    { id: 'transactions', label: 'Financeiro', icon: Receipt },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle },
    { id: 'tasks', label: 'Tarefas', icon: CheckSquare },
    { id: 'calendar', label: 'Agenda', icon: CalendarIcon },
    { id: 'notes', label: 'Notas', icon: FileText },
    { id: 'journal', label: 'Diário', icon: BookOpen },
    { id: 'potes', label: 'Config. Potes', icon: Archive },
    { id: 'advisor', label: 'ZenAdvisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100 font-sans overflow-hidden">
      <aside className={`fixed md:sticky top-0 h-screen z-30 transition-all duration-300 ${isSidebarOpen ? 'w-64 translate-x-0' : 'w-0 -translate-x-full md:w-20 md:translate-x-0'} bg-[#0a0c14] border-r border-slate-800 flex flex-col`}>
        <div className="p-6 flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
          {isSidebarOpen && <span className="text-xl font-bold tracking-tight text-white">ZenOS</span>}
        </div>
        <nav className="flex-1 px-3 mt-4 space-y-1 overflow-y-auto">
          {navItems.map((item) => (
            <button key={item.id} onClick={() => setView(item.id as AppView)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl transition-all ${view === item.id ? 'bg-indigo-600/10 text-indigo-400 border border-indigo-500/20' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800/40'}`}>
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {isSidebarOpen && <span className="font-bold text-sm tracking-wide">{item.label}</span>}
            </button>
          ))}
        </nav>
        <div className="p-4 border-t border-slate-800">
           <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-full flex items-center justify-center p-2.5 rounded-xl hover:bg-slate-800 transition-colors">
            {isSidebarOpen ? <X className="w-4 h-4 text-slate-600" /> : <Menu className="w-4 h-4 text-slate-600" />}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen">
        <header className="h-16 glass sticky top-0 z-10 px-8 flex items-center justify-between">
          <h1 className="text-xl font-black text-white uppercase tracking-widest">{navItems.find(i => i.id === view)?.label}</h1>
          <div className="flex items-center gap-4">
             <div className="hidden md:flex flex-col text-right">
                <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Master Engine v2.0</span>
                <span className="text-[11px] text-indigo-400 font-bold">Consistência: Absoluta</span>
             </div>
             <div className="w-10 h-10 rounded-2xl bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <BrainCircuit className="w-5 h-5 text-indigo-400" />
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 pb-12">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && (
            <Transactions 
              transactions={transactions} 
              potes={processedPotes} 
              onAdd={(t) => setTransactions([t, ...transactions])} 
              onDelete={(id) => { if(window.confirm('Excluir transação permanentemente?')) setTransactions(transactions.filter(t => t.id !== id)); }}
              onEdit={(updated) => setTransactions(transactions.map(t => t.id === updated.id ? updated : t))}
            />
          )}
          {view === 'debts' && (
            <Debts 
              debts={debts} potes={processedPotes}
              onAdd={(d) => setDebts([...debts, d])}
              onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))}
              onPay={(d, amt, pId) => {
                 const updatedDebt = { ...d, remainingAmount: d.remainingAmount - amt };
                 if (updatedDebt.remainingAmount <= 0) updatedDebt.status = 'paid' as any;
                 setDebts(debts.map(item => item.id === d.id ? updatedDebt : item));
                 setTransactions([{
                    id: Math.random().toString(36).substr(2, 9),
                    description: `Pagamento: ${d.name}`,
                    amount: amt,
                    category: 'Dívidas',
                    date: new Date().toISOString().split('T')[0],
                    type: 'expense',
                    poteId: pId
                 }, ...transactions]);
              }}
            />
          )}
          {view === 'tasks' && <Tasks tasks={tasks} onUpdate={setTasks} />}
          {view === 'notes' && <Notes notes={notes} onUpdate={setNotes} />}
          {view === 'journal' && <Journal journal={journal} onUpdate={setJournal} />}
          {view === 'potes' && <Potes potes={potes} onUpdate={setPotes} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

