import React, { useState } from 'react';
import { Search, Plus, Minus, ArrowUpCircle, ArrowDownCircle, X, Trash2, Edit2, CreditCard, Tag, AlertCircle } from 'lucide-react';
import { Transaction, TransactionType, Jar } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
}

export default function Transactions({ transactions, potes, onAdd, onDelete, onEdit }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '', amount: 0, category: 'Geral', type: 'expense', date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : '', paymentMethod: 'PIX', isRecurring: false
  });

  const filteredTransactions = transactions.filter(t => {
    const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          t.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = typeFilter === 'all' || t.type === typeFilter;
    return matchesSearch && matchesType;
  });

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '', amount: 0, category: type === 'income' ? 'Salário' : 'Consumo', type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : '',
      paymentMethod: 'PIX', isRecurring: false
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount) return;
    if (currentTx.type === 'expense' && !currentTx.poteId) {
       alert("ERRO: Selecione obrigatoriamente um pote de origem.");
       return;
    }

    if (modalType === 'add') {
      onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    } else if (modalType === 'edit') {
