import React, { useState } from 'react';
import { Jar } from '../types';
import { Plus, Trash2, Edit2, Archive, X, Save, Settings } from 'lucide-react';

interface PotesProps {
  potes: Jar[];
  onUpdate: (potes: Jar[]) => void;
}

export default function Potes({ potes, onUpdate }: PotesProps) {
  const [showModal, setShowModal] = useState<'add' | 'edit' | null>(null);
  const [currentPote, setCurrentPote] = useState<Partial<Jar>>({ name: '', percentage: 0 });

  const totalPercentage = potes.reduce((acc, p) => acc + p.percentage, 0);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const otherPotes = showModal === 'edit' ? potes.filter(p => p.id !== currentPote.id) : potes;
    const currentTotal = otherPotes.reduce((acc, p) => acc + p.percentage, 0);

    if (currentTotal + (currentPote.percentage || 0) > 100) { 
      alert("ERRO: A soma total das porcentagens não pode exceder 100%!"); 
      return; 
    }

    if (showModal === 'add') {
      const pote: Jar = { 
        id: Math.random().toString(36).substr(2, 9), 
        name: currentPote.name || 'Novo Pote', 
        percentage: currentPote.percentage || 0, 
        balance: 0 
      };
      onUpdate([...potes, pote]);
    } else {
      onUpdate(potes.map(p => p.id === currentPote.id ? { ...p, ...currentPote } as Jar : p));
    }
    setShowModal(null);
  };

  return (
    <div className="space-y-8">
      {/* Resumo da Estrutura */}
      <div className="bg-[#0a0c14] p-8 rounded-[2.5rem] border border-white/5 flex flex-col md:flex-row items-center justify-between gap-6 shadow-2xl">
        <div className="flex items-center gap-5">
           <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-600/20">
              <Settings className="w-8 h-8 text-indigo-400" />
           </div>
           <div>
              <h2 className="text-xl font-black text-white uppercase tracking-tighter">Arquitetura de Rateio</h2>
              <p className="text-slate-500 text-[11px] font-bold uppercase tracking-[0.2em] mt-1">
                Alocação: <span className={`px-2 py-0.5 rounded-lg ${totalPercentage > 100 ? 'bg-rose-500/20 text-rose-400' : 'bg-indigo-500/10 text-indigo-400'}`}>{totalPercentage}% / 100%</span>
              </p>
           </div>
        </div>
        <button 
          onClick={() => { setCurrentPote({ name: '', percentage: 0 }); setShowModal('add'); }}
          className="w-full md:w-auto flex items-center justify-center gap-3 px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
        >
          <Plus className="w-5 h-5" /> Adicionar Pote
        </button>
      </div>

      {/* Grid de Potes Editáveis */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {potes.map((pote) => (
          <div key={pote.id} className="bg-[#111827]/40 p-6 rounded-[2rem] border border-white/5 group relative overflow-hidden transition-all hover:border-indigo-500/30">
            <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
              <button onClick={() => { setCurrentPote(pote); setShowModal('edit'); }} className="p-2 text-slate-600 hover:text-indigo-400 hover:bg-white/5 rounded-xl"><Edit2 className="w-4 h-4" /></button>
              <button onClick={() => { if(confirm(`Excluir ${pote.name}? As transações vinculadas perderão a referência de pote.`)) onUpdate(potes.filter(p => p.id !== pote.id)) }} className="p-2 text-slate-600 hover:text-rose-500 hover:bg-white/5 rounded-xl"><Trash2 className="w-4 h-4" /></button>
            </div>

            <div className="bg-indigo-500/10 w-12 h-12 flex items-center justify-center rounded-2xl border border-indigo-500/20 mb-6">
              <Archive className="w-6 h-6 text-indigo-400" />
            </div>

            <h3 className="text-lg font-black text-white mb-1 tracking-tight truncate pr-10">{pote.name}</h3>
            <span className="text-[10px] font-black text-indigo-500/80 uppercase tracking-widest block mb-4">Rateio: {pote.percentage}%</span>

            <div className="pt-4 border-t border-white/5">
              <p className="text-[9px] text-slate-600 uppercase font-black tracking-widest mb-1">Saldo Atual (Live)</p>
              <p className={`text-2xl font-black tracking-tighter ${pote.balance >= 0 ? 'text-slate-200' : 'text-rose-500'}`}>
                R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </p>
            </div>
          </div>
        ))}
      </div>

      {/* Modal de Configuração de Pote */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/95 backdrop-blur-md">
          <div className="bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-white uppercase tracking-tighter">Configurar Pote</h3>
              <button onClick={() => setShowModal(null)} className="p-2 hover:bg-white/5 rounded-full"><X className="w-5 h-5 text-slate-600" /></button>
            </div>
            <form onSubmit={handleSave} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Identificação</label>
                <input type="text" required className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentPote.name} onChange={e => setCurrentPote({...currentPote, name: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Percentual de Entrada (%)</label>
                <div className="relative">
                  <input type="number" required min="0" max="100" className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentPote.percentage || ''} onChange={e => setCurrentPote({...currentPote, percentage: parseInt(e.target.value) || 0})} />
                  <span className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-600 font-black">%</span>
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(null)} className="flex-1 py-4 text-slate-600 font-black uppercase text-xs tracking-widest hover:text-white transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-indigo-500 shadow-xl transition-all">
                  Confirmar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, Receipt, Target, Wallet, BrainCircuit, Menu, X, Archive, 
