} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Task, Note, JournalEntry, CalendarEvent } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Tasks from './components/Tasks';
import Notes from './components/Notes';
import Journal from './components/Journal';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Investimento/Reserva', percentage: 20, balance: 0 },
];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

const SEED_TASKS: Task[] = [
  { id: 'task1', title: 'Revisar portfólio de investimentos', completed: false, priority: 'high', dueDate: new Date().toISOString().split('T')[0], tags: ['finanças'] },
  { id: 'task2', title: 'Comprar presente de aniversário', completed: false, priority: 'medium', dueDate: new Date().toISOString().split('T')[0], tags: ['pessoal'] },
];

const SEED_NOTES: Note[] = [
  { id: 'note1', title: 'Ideia: App de Meditação', content: 'Criar algo que conecte batimentos cardíacos com trilhas sonoras generativas.', date: new Date().toISOString(), tags: ['ideias'] },
];

const SEED_JOURNAL: JournalEntry[] = [
  { id: 'j1', content: 'Hoje comecei o dia com muita energia e focado em organizar minha vida financeira.', mood: 'Focused', date: new Date().toISOString() },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Estados dos Módulos com Initial Seed
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => {
    const saved = localStorage.getItem('zen_debts');
    return saved ? JSON.parse(saved) : [
      { id: 'd1', name: 'Parcela iPhone 15', totalAmount: 5000, remainingAmount: 2500, dueDate: '2024-12-10', category: 'Eletrônicos', status: 'active' }
    ];
  });

  const [tasks, setTasks] = useState<Task[]>(() => {
    const saved = localStorage.getItem('zen_tasks');
    return saved ? JSON.parse(saved) : SEED_TASKS;
  });

  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('zen_notes');
    return saved ? JSON.parse(saved) : SEED_NOTES;
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('zen_journal');
    return saved ? JSON.parse(saved) : SEED_JOURNAL;
  });

  const [events, setEvents] = useState<CalendarEvent[]>(() => JSON.parse(localStorage.getItem('zen_events') || '[]'));

  // Persistência
  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_tasks', JSON.stringify(tasks));
    localStorage.setItem('zen_notes', JSON.stringify(notes));
    localStorage.setItem('zen_journal', JSON.stringify(journal));
    localStorage.setItem('zen_events', JSON.stringify(events));
  }, [transactions, potes, debts, tasks, notes, journal, events]);

  const processedPotes = useMemo(() => {
    return potes.map(pote => {
      let balance = 0;
      transactions.forEach(t => {
        if (t.type === 'income') {
          balance += t.amount * (pote.percentage / 100);
        } else if (t.type === 'expense' && t.poteId === pote.id) {
          balance -= t.amount;
        }
      });
      return { ...pote, balance };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, tasks, notes, journal, events,
    budgets: [], goals: [] 
  }), [transactions, processedPotes, debts, tasks, notes, journal, events]);

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'Finanças', icon: Receipt },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle },
    { id: 'tasks', label: 'Tarefas', icon: CheckSquare },
    { id: 'notes', label: 'Notas', icon: FileText },
    { id: 'journal', label: 'Diário', icon: BookOpen },
    { id: 'potes', label: 'Gestão de Potes', icon: Archive },
    { id: 'advisor', label: 'ZenAdvisor AI', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100 font-sans overflow-hidden">
      {/* Sidebar ZenOS */}
      <aside className={`fixed md:sticky top-0 h-screen z-30 transition-all duration-300 ${isSidebarOpen ? 'w-64 translate-x-0' : 'w-0 -translate-x-full md:w-20 md:translate-x-0'} bg-[#0a0c14] border-r border-slate-800 flex flex-col`}>
        <div className="p-6 flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
          {isSidebarOpen && <span className="text-xl font-bold tracking-tight text-white">ZenOS</span>}
        </div>
        <nav className="flex-1 px-3 mt-4 space-y-1 overflow-y-auto">
          {navItems.map((item) => (
            <button key={item.id} onClick={() => setView(item.id as AppView)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl transition-all ${view === item.id ? 'bg-indigo-600/10 text-indigo-400 border border-indigo-500/20' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800/40'}`}>
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {isSidebarOpen && <span className="font-bold text-sm tracking-wide">{item.label}</span>}
            </button>
          ))}
        </nav>
        <div className="p-4 border-t border-slate-800">
           <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-full flex items-center justify-center p-2.5 rounded-xl hover:bg-slate-800 transition-colors">
            {isSidebarOpen ? <X className="w-4 h-4 text-slate-600" /> : <Menu className="w-4 h-4 text-slate-600" />}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen">
        <header className="h-16 glass sticky top-0 z-10 px-8 flex items-center justify-between">
          <h1 className="text-xl font-black text-white uppercase tracking-widest">{navItems.find(i => i.id === view)?.label}</h1>
          <div className="flex items-center gap-4">
             <div className="hidden md:flex flex-col text-right">
                <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Master OS Active</span>
                <span className="text-[11px] text-indigo-400 font-bold">System: Stable</span>
             </div>
             <div className="w-10 h-10 rounded-2xl bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <BrainCircuit className="w-5 h-5 text-indigo-400" />
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 pb-12">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && (
            <Transactions 
              transactions={transactions} 
              potes={processedPotes} 
              onAdd={(t) => setTransactions([t, ...transactions])} 
              onDelete={(id) => setTransactions(transactions.filter(t => t.id !== id))}
              onEdit={(updated) => setTransactions(transactions.map(t => t.id === updated.id ? updated : t))}
            />
          )}
          {view === 'debts' && (
            <Debts 
              debts={debts} potes={processedPotes}
              onAdd={(d) => setDebts([...debts, d])}
              onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))}
              onPay={(d, amt, pId) => {
                 const updatedDebt = { ...d, remainingAmount: d.remainingAmount - amt };
                 if (updatedDebt.remainingAmount <= 0) updatedDebt.status = 'paid' as any;
                 setDebts(debts.map(item => item.id === d.id ? updatedDebt : item));
                 setTransactions([{
                    id: Math.random().toString(36).substr(2, 9),
                    description: `Pgmto Dívida: ${d.name}`,
                    amount: amt,
                    category: 'Dívidas',
                    date: new Date().toISOString().split('T')[0],
                    type: 'expense',
                    poteId: pId
                 }, ...transactions]);
              }}
            />
          )}
          {view === 'tasks' && <Tasks tasks={tasks} onUpdate={setTasks} />}
          {view === 'notes' && <Notes notes={notes} onUpdate={setNotes} />}
          {view === 'journal' && <Journal journal={journal} onUpdate={setJournal} />}
          {view === 'potes' && <Potes potes={potes} onUpdate={setPotes} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { BrainCircuit, Send, Loader2, Sparkles, MessageSquare } from 'lucide-react';
import { FinancialData } from '../types';
import { getFinancialAdvice } from '../services/gemini';

interface Message {
  id: string;
  role: 'user' | 'ai';
  content: string;
}

export default function AIAdvisor({ data }: { data: FinancialData }) {
  const [messages, setMessages] = useState<Message[]>([
    { id: '1', role: 'ai', content: 'Iniciando ZenOS Master Engine... Análise de dados completa. Estou pronto para gerenciar sua vida produtiva e financeira. O que vamos otimizar hoje?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage: Message = { id: Date.now().toString(), role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const advice = await getFinancialAdvice(data, input);
    const aiMessage: Message = { id: (Date.now() + 1).toString(), role: 'ai', content: advice || 'Houve uma falha na sincronização neural.' };

    setMessages(prev => [...prev, aiMessage]);
    setIsLoading(false);
  };

  return (
    <div className="h-[calc(100vh-12rem)] flex flex-col bg-[#0a0c14] rounded-[3rem] border border-white/5 overflow-hidden shadow-2xl animate-in zoom-in duration-500">
      {/* Advisor Header */}
      <div className="bg-indigo-600/90 p-8 text-white flex items-center gap-6 border-b border-indigo-500/20 backdrop-blur-xl">
        <div className="bg-white/10 p-4 rounded-[1.5rem] backdrop-blur-md border border-white/10">
          <BrainCircuit className="w-8 h-8 text-white" />
        </div>
        <div>
          <h2 className="text-2xl font-black uppercase tracking-tighter">ZenOS Master Advisor</h2>
          <p className="text-indigo-100/60 text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-2 mt-1">
            <span className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></span>
            Interface Neural Ativa
          </p>
        </div>
      </div>

      {/* Chat Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-8 space-y-8 bg-[#030712]/50 custom-scrollbar"
      >
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`
              max-w-[85%] rounded-[2rem] p-6 shadow-2xl transition-all
              ${msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none border border-indigo-400/20' 
                : 'bg-[#111827] text-slate-100 border border-white/5 rounded-tl-none'}
            `}>
              {msg.role === 'ai' && (
                <div className="flex items-center gap-2 mb-4 text-indigo-400 text-[9px] font-black uppercase tracking-[0.3em]">
                  <Sparkles className="w-3.5 h-3.5" /> Insights Processados
                </div>
              )}
              <div className="prose prose-invert prose-sm max-w-none text-slate-300 leading-relaxed font-medium">
                {msg.content}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-[#111827] p-6 rounded-[2rem] border border-white/5 flex items-center gap-4">
              <Loader2 className="w-5 h-5 text-indigo-500 animate-spin" />
              <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Calculando Probabilidades...</span>
            </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-6 bg-[#0a0c14] border-t border-white/5">
        <form onSubmit={handleSend} className="relative group">
          <input 
            type="text"
            placeholder="Comando master (ex: 'Resuma minha saúde financeira')"
            className="w-full pl-8 pr-20 py-5 bg-slate-900/60 border border-white/5 rounded-[2rem] text-white focus:outline-none focus:ring-2 focus:ring-indigo-600 focus:bg-slate-900 transition-all placeholder:text-slate-700"
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button 
            type="submit"
            disabled={!input.trim() || isLoading}
            className={`
              absolute right-3 top-1/2 -translate-y-1/2 p-4 rounded-[1.5rem] transition-all
              ${input.trim() && !isLoading ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30 scale-100' : 'bg-slate-800 text-slate-600 scale-95 opacity-50'}
            `}
          >
            <Send className="w-5 h-5" />
          </button>
        </form>
        <div className="mt-4 flex flex-wrap justify-center gap-3">
          {['Relatório Financeiro', 'Dicas de Economia', 'Resumo de Tarefas'].map((hint) => (
            <button 
              key={hint}
              onClick={() => setInput(hint)}
              className="text-[9px] font-black text-slate-500 uppercase tracking-widest px-4 py-2 bg-slate-900/40 rounded-xl border border-white/5 hover:text-indigo-400 hover:border-indigo-500/20 transition-all"
            >
              {hint}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

