import React, { useState, useMemo } from 'react';
import { Search, Plus, Minus, ArrowUpCircle, ArrowDownCircle, X, Trash2, Edit2, Calendar, CreditCard, Tag, Filter, ArrowUpDown } from 'lucide-react';
import { Transaction, TransactionType, Jar } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
}

type SortOption = 'date-desc' | 'date-asc' | 'amount-desc' | 'amount-asc';

export default function Transactions({ transactions, potes, onAdd, onDelete, onEdit }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [sortOption, setSortOption] = useState<SortOption>('date-desc');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '', amount: 0, category: 'Geral', type: 'expense', date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : '', paymentMethod: 'PIX'
  });

  const filteredTransactions = useMemo(() => {
    let result = transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = typeFilter === 'all' || t.type === typeFilter;

      const txDate = new Date(t.date).getTime();
      const matchesStartDate = !startDate || txDate >= new Date(startDate).getTime();
      const matchesEndDate = !endDate || txDate <= new Date(endDate).getTime();

      return matchesSearch && matchesType && matchesStartDate && matchesEndDate;
    });

    result.sort((a, b) => {
      switch (sortOption) {
        case 'date-desc':
          return new Date(b.date).getTime() - new Date(a.date).getTime();
        case 'date-asc':
          return new Date(a.date).getTime() - new Date(b.date).getTime();
        case 'amount-desc':
          return b.amount - a.amount;
        case 'amount-asc':
          return a.amount - b.amount;
        default:
          return 0;
      }
    });

    return result;
  }, [transactions, searchTerm, typeFilter, startDate, endDate, sortOption]);

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '', amount: 0, category: type === 'income' ? 'Salário' : 'Consumo', type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : '',
      paymentMethod: 'PIX'
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount) return;
    if (currentTx.type === 'expense' && !currentTx.poteId) {
       alert("Selecione um pote.");
       return;
    }
    if (modalType === 'add') onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    else if (modalType === 'edit') onEdit(currentTx as Transaction);
    setModalType(null);
  };

  return (
    <div className="space-y-6">
      {/* Botões de Ação Rápida */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 md:gap-4">
        <button 
          onClick={() => handleOpenAdd('income')}
          className="group flex items-center justify-center gap-3 py-5 md:py-6 bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 rounded-2xl md:rounded-3xl hover:bg-emerald-500/20 transition-all font-black uppercase text-[10px] md:text-xs tracking-widest"
        >
          <Plus className="w-5 h-5" /> Entrada
        </button>
        <button 
          onClick={() => handleOpenAdd('expense')}
          className="group flex items-center justify-center gap-3 py-5 md:py-6 bg-rose-500/10 border border-rose-500/20 text-rose-400 rounded-2xl md:rounded-3xl hover:bg-rose-500/20 transition-all font-black uppercase text-[10px] md:text-xs tracking-widest"
        >
          <Minus className="w-5 h-5" /> Despesa
        </button>
      </div>

      {/* Busca e Filtros */}
      <div className="bg-slate-900/40 p-4 md:p-6 rounded-2xl md:rounded-3xl border border-white/5 space-y-4">
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="relative flex-1 w-full">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
            <input 
              type="text" 
              placeholder="Pesquisar por descrição ou categoria..."
              className="w-full pl-11 pr-6 py-3 bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 text-sm outline-none focus:ring-1 focus:ring-indigo-500/50 transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => setIsFilterExpanded(!isFilterExpanded)}
            className={`flex items-center gap-2 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-950/50 text-slate-400 border-white/5 hover:bg-slate-900'}`}
          >
            <Filter className="w-4 h-4" /> Filtros {isFilterExpanded ? <X className="w-3 h-3 ml-1" /> : null}
          </button>
        </div>

        {isFilterExpanded && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-4 border-t border-white/5 animate-in slide-in-from-top-2 duration-200">
            <div className="space-y-2">
              <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest px-1">Período De</label>
              <input 
                type="date" 
                className="w-full px-4 py-2 bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 text-xs outline-none focus:ring-1 focus:ring-indigo-500/50"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest px-1">Até</label>
              <input 
                type="date" 
                className="w-full px-4 py-2 bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 text-xs outline-none focus:ring-1 focus:ring-indigo-500/50"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest px-1">Ordenar Por</label>
              <div className="relative">
                <ArrowUpDown className="absolute right-4 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-600 pointer-events-none" />
                <select 
                  className="w-full px-4 py-2 bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 text-xs outline-none appearance-none focus:ring-1 focus:ring-indigo-500/50"
                  value={sortOption}
                  onChange={(e) => setSortOption(e.target.value as SortOption)}
                >
                  <option value="date-desc">Mais recente</option>
                  <option value="date-asc">Mais antigo</option>
                  <option value="amount-desc">Maior valor</option>
                  <option value="amount-asc">Menor valor</option>
                </select>
              </div>
            </div>
          </div>
        )}

        <div className="flex overflow-x-auto gap-2 pb-1 scrollbar-hide pt-2">
          {['all', 'income', 'expense'].map((f) => (
            <button key={f} onClick={() => setTypeFilter(f as any)} className={`whitespace-nowrap px-5 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${typeFilter === f ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'bg-slate-950/50 text-slate-500 border border-white/5 hover:text-slate-300'}`}>
              {f === 'all' ? 'Tudo' : f === 'income' ? 'Entradas' : 'Saídas'}
            </button>
          ))}
          {(searchTerm || typeFilter !== 'all' || startDate || endDate) && (
             <button 
              onClick={() => { setSearchTerm(''); setTypeFilter('all'); setStartDate(''); setEndDate(''); }}
              className="whitespace-nowrap px-4 py-2 text-[9px] font-black uppercase tracking-widest text-rose-500 hover:bg-rose-500/10 rounded-xl transition-all"
             >
               Limpar Filtros
             </button>
          )}
        </div>
      </div>

      {/* Mobile Card List (Visible only on mobile) */}
      <div className="block lg:hidden space-y-3">
        {filteredTransactions.length === 0 ? (
          <div className="bg-[#0a0c14] p-8 rounded-2xl border border-white/5 text-center">
            <p className="text-slate-600 text-xs font-bold uppercase tracking-widest">Nenhuma transação encontrada</p>
          </div>
        ) : filteredTransactions.map(t => (
          <div key={t.id} className="bg-[#0a0c14] p-4 rounded-2xl border border-white/5 flex flex-col gap-3 group animate-in fade-in duration-300">
            <div className="flex justify-between items-start">
              <div className="flex gap-3">
                <div className={`p-2 rounded-lg ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                  {t.type === 'income' ? <Plus className="w-4 h-4" /> : <Minus className="w-4 h-4" />}
                </div>
                <div>
                  <p className="font-bold text-slate-200 text-sm">{t.description}</p>
                  <p className="text-[9px] text-slate-600 font-black uppercase">{t.category} • {new Date(t.date).toLocaleDateString('pt-BR')}</p>
                </div>
              </div>
              <p className={`font-black text-sm ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-200'}`}>
                R$ {t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </p>
            </div>
            <div className="flex justify-between items-center border-t border-white/5 pt-3">
              <span className="text-[9px] font-black text-indigo-400 uppercase">
                {t.type === 'income' ? 'RATEIO' : (potes.find(p => p.id === t.poteId)?.name || 'OUTRO')}
              </span>
              <div className="flex gap-2">
                <button onClick={() => handleOpenEdit(t)} className="p-2 text-slate-600 bg-slate-900 rounded-lg"><Edit2 className="w-3.5 h-3.5" /></button>
                <button onClick={() => onDelete(t.id)} className="p-2 text-rose-500/50 bg-rose-500/5 rounded-lg"><Trash2 className="w-3.5 h-3.5" /></button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Desktop Table (Hidden on mobile) */}
      <div className="hidden lg:block bg-[#0a0c14] rounded-[2rem] border border-white/5 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-white/5 border-b border-white/5 text-[10px] font-black text-slate-500 uppercase tracking-widest">
              <th className="px-8 py-5">Transação</th>
              <th className="px-8 py-5">Data</th>
              <th className="px-8 py-5">Alocação</th>
              <th className="px-8 py-5 text-right">Montante</th>
              <th className="px-8 py-5 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-white/5">
            {filteredTransactions.length === 0 ? (
              <tr>
                <td colSpan={5} className="px-8 py-10 text-center text-slate-600 text-xs font-bold uppercase tracking-widest">
                  Nenhuma transação encontrada
                </td>
              </tr>
            ) : filteredTransactions.map(t => (
              <tr key={t.id} className="hover:bg-white/5 group transition-colors animate-in fade-in duration-300">
                <td className="px-8 py-5 flex items-center gap-4">
                  <div className={`p-2 rounded-lg ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                    {t.type === 'income' ? <Plus className="w-4 h-4" /> : <Minus className="w-4 h-4" />}
                  </div>
                  <div>
                    <p className="font-bold text-slate-200 text-sm">{t.description}</p>
                    <p className="text-[9px] text-slate-600 font-black uppercase">{t.category}</p>
                  </div>
                </td>
                <td className="px-8 py-5 text-xs text-slate-400 font-bold">
                  {new Date(t.date).toLocaleDateString('pt-BR')}
                </td>
                <td className="px-8 py-5 text-[10px] font-black uppercase tracking-widest text-indigo-400">
                  {t.type === 'income' ? 'Rateio Global' : (potes.find(p => p.id === t.poteId)?.name || '-')}
                </td>
                <td className={`px-8 py-5 text-right font-black ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-200'}`}>
                  R$ {t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
                <td className="px-8 py-5">
                  <div className="flex justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                    <button onClick={() => handleOpenEdit(t)} className="p-2 text-slate-600 hover:text-indigo-400"><Edit2 className="w-4 h-4" /></button>
                    <button onClick={() => onDelete(t.id)} className="p-2 text-slate-600 hover:text-rose-500"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Modal - Full screen on mobile */}
      {modalType && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-0 md:p-4 bg-black/95 backdrop-blur-md overflow-y-auto">
          <div className="bg-[#111827] w-full h-full md:h-auto md:max-w-lg md:rounded-[2.5rem] p-8 md:p-10 border-white/10 flex flex-col animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-white uppercase tracking-tighter">{modalType === 'add' ? 'Novo Registro' : 'Editar'}</h3>
              <button onClick={() => setModalType(null)} className="p-2 bg-slate-900 rounded-full"><X className="w-6 h-6 text-slate-500" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6 flex-1">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Descrição</label>
                <input placeholder="Ex: Salário, Aluguel, Café..." required className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={currentTx.description} onChange={e => setCurrentTx({...currentTx, description: e.target.value})} />
              </div>

              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Valor R$</label>
                <input type="number" step="0.01" placeholder="0,00" required className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={currentTx.amount || ''} onChange={e => setCurrentTx({...currentTx, amount: parseFloat(e.target.value)})} />
              </div>

              {currentTx.type === 'expense' && (
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Pote de Origem</label>
                  <select className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={currentTx.poteId} onChange={e => setCurrentTx({...currentTx, poteId: e.target.value})}>
                    <option value="">Selecione o Pote</option>
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name} (R$ {p.balance.toLocaleString()})</option>)}
                  </select>
                </div>
              )}

              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Data</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={currentTx.date} onChange={e => setCurrentTx({...currentTx, date: e.target.value})} />
              </div>

              <div className="flex gap-4 pt-10 mt-auto md:mt-0">
                <button type="button" onClick={() => setModalType(null)} className="flex-1 py-4 text-slate-600 font-black uppercase text-[10px] tracking-widest hover:text-slate-400 transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white font-black uppercase text-[10px] tracking-widest rounded-2xl shadow-xl shadow-indigo-600/20 active:scale-95 transition-transform">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useMemo } from 'react';
import { Wallet, TrendingUp, PieChart as PieChartIcon, BarChart3, Activity } from 'lucide-react';
import { FinancialData, Transaction } from '../types';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend 
} from 'recharts';

interface DashboardProps {
  data: FinancialData;
}

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f59e0b', '#10b981', '#06b6d4'];

export default function Dashboard({ data }: DashboardProps) {
  const { transactions, potes, tasks, journal } = data;

  const totalBalance = potes.reduce((acc, p) => acc + p.balance, 0);

  const now = new Date();
  const monthIncome = transactions
    .filter(t => t.type === 'income' && new Date(t.date).getMonth() === now.getMonth())
    .reduce((acc, t) => acc + t.amount, 0);

  const pendingTasks = tasks.filter(t => !t.completed);
  const latestEntry = journal[0];

  // Processar dados para Gráfico de Pizza (Categorias de Gastos)
  const categoryData = useMemo(() => {
    const expenses = transactions.filter(t => t.type === 'expense');
    const categories: Record<string, number> = {};

    expenses.forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });

    return Object.entries(categories)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 6); // Top 6 categorias
  }, [transactions]);

  // Processar dados para Gráfico de Barras (Tendência Mensal)
  const trendData = useMemo(() => {
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const last6Months = [];

    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(d.getMonth() - i);
      const monthIndex = d.getMonth();
      const year = d.getFullYear();

      const income = transactions
        .filter(t => t.type === 'income' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);

      const expense = transactions
        .filter(t => t.type === 'expense' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);

      last6Months.push({
        name: months[monthIndex],
        Entradas: income,
        Saídas: expense
      });
    }
    return last6Months;
  }, [transactions]);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-[#0f172a] border border-white/10 p-3 rounded-xl shadow-2xl backdrop-blur-md">
          <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">{payload[0].name || payload[0].dataKey}</p>
          <p className="text-sm font-bold text-white">
            R$ {payload[0].value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-700 pb-12">
      {/* Indicadores Financeiros Master */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-900 p-6 md:p-8 rounded-[2rem] md:rounded-[2.5rem] shadow-2xl relative overflow-hidden group border border-white/10">
           <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-125 transition-transform duration-700"><Wallet className="w-16 h-16 md:w-24 md:h-24" /></div>
           <span className="text-indigo-100/60 text-[10px] md:text-[11px] font-black uppercase tracking-[0.2em] block mb-2">Liquidez ZenOS</span>
           <p className={`text-3xl md:text-5xl font-black tracking-tighter ${totalBalance < 0 ? 'text-rose-400' : 'text-white'}`}>
             R$ {totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
           <div className="mt-4 flex items-center gap-2">
              <div className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></div>
              <span className="text-[9px] md:text-[10px] text-indigo-200/50 font-bold uppercase tracking-widest">Motor Live</span>
           </div>
        </div>

        <div className="bg-[#111827]/60 p-6 md:p-8 rounded-[2rem] md:rounded-[2.5rem] border border-white/5 relative group overflow-hidden hover:border-emerald-500/20 transition-all">
           <div className="absolute top-0 right-0 p-8 opacity-5"><TrendingUp className="w-16 h-16 md:w-24 md:h-24" /></div>
           <div className="flex items-center gap-3 mb-4">
              <div className="p-2 bg-emerald-500/10 rounded-xl"><TrendingUp className="w-5 h-5 text-emerald-400" /></div>
              <span className="text-slate-500 text-[10px] md:text-[11px] font-black uppercase tracking-[0.2em]">Faturamento Mês</span>
           </div>
           <p className="text-3xl md:text-5xl font-black text-emerald-400 tracking-tighter">
             R$ {monthIncome.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
        </div>
      </div>

      {/* Seção de Gráficos Interativos */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        {/* Distribuição por Categoria */}
        <div className="bg-[#0a0c14] p-6 md:p-8 rounded-[2rem] border border-white/5 shadow-xl flex flex-col">
          <h3 className="text-[10px] md:text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-6 flex items-center gap-3">
            <PieChartIcon className="w-4 h-4 text-indigo-400" /> Mix de Consumo
          </h3>
          <div className="h-64 w-full">
            {categoryData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={categoryData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {categoryData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip content={<CustomTooltip />} />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-600 text-[10px] font-black uppercase italic">Sem despesas registradas</div>
            )}
          </div>
          <div className="grid grid-cols-2 gap-2 mt-4">
            {categoryData.map((entry, index) => (
              <div key={entry.name} className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[index % COLORS.length] }} />
                <span className="text-[9px] font-bold text-slate-400 uppercase truncate">{entry.name}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Fluxo de Caixa Mensal */}
        <div className="bg-[#0a0c14] p-6 md:p-8 rounded-[2rem] border border-white/5 shadow-xl">
          <h3 className="text-[10px] md:text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-6 flex items-center gap-3">
            <BarChart3 className="w-4 h-4 text-indigo-400" /> Tendência de Fluxo
          </h3>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={trendData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                <XAxis 
                  dataKey="name" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#475569', fontSize: 10, fontWeight: 800 }} 
                />
                <YAxis hide />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(255,255,255,0.05)' }} />
                <Bar dataKey="Entradas" fill="#10b981" radius={[4, 4, 0, 0]} />
                <Bar dataKey="Saídas" fill="#f43f5e" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
          <div className="flex justify-center gap-6 mt-4">
            <div className="flex items-center gap-2">
              <div className="w-3 h-3 bg-emerald-500 rounded" />
              <span className="text-[9px] font-black text-slate-500 uppercase">Ganhos</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-3 h-3 bg-rose-500 rounded" />
              <span className="text-[9px] font-black text-slate-500 uppercase">Gastos</span>
            </div>
          </div>
        </div>
      </div>

      {/* Grid de Potes em 2 Colunas */}
      <div className="space-y-4">
        <h3 className="text-[10px] md:text-[11px] font-black text-slate-500 uppercase tracking-[0.3em] px-2 flex items-center gap-4">
          Potes <div className="h-px flex-1 bg-slate-800"></div>
        </h3>
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4">
          {potes.map((pote) => (
            <div key={pote.id} className="bg-[#0a0c14] p-4 md:p-5 rounded-2xl md:rounded-3xl border border-white/5 hover:border-indigo-500/40 transition-all shadow-xl group">
               <div className="flex justify-between items-center mb-3">
                  <span className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest truncate">{pote.name}</span>
                  <span className="text-[8px] md:text-[9px] font-bold text-indigo-400 bg-indigo-500/10 px-1.5 py-0.5 rounded-lg">{pote.percentage}%</span>
               </div>
               <p className={`text-sm md:text-xl font-bold tracking-tighter ${pote.balance < 0 ? 'text-rose-500' : 'text-slate-200'}`}>
                 R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
               </p>
               <div className="mt-3 h-1 w-full bg-slate-900 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-1000" style={{ width: `${Math.max(0, Math.min(100, pote.percentage))}%` }}></div>
               </div>
            </div>
          ))}
        </div>
      </div>

      {/* Seção Operacional 360º */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
        <div className="lg:col-span-2 space-y-4">
          <div className="flex items-center justify-between px-2">
            <h3 className="text-[10px] md:text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] flex items-center gap-3">
              Tarefas <div className="h-px w-12 bg-slate-800"></div>
            </h3>
          </div>
          <div className="grid grid-cols-1 gap-3">
            {pendingTasks.slice(0, 3).map(task => (
              <div key={task.id} className="bg-[#111827]/40 p-4 md:p-5 rounded-2xl md:rounded-3xl border border-white/5 flex items-center justify-between group hover:bg-slate-900 transition-all">
                <div className="flex items-center gap-3 md:gap-4">
                  <Activity className={`w-4 h-4 md:w-5 md:h-5 ${task.priority === 'high' ? 'text-rose-500' : 'text-indigo-500'}`} />
                  <span className="text-xs md:text-sm font-bold text-slate-300">{task.title}</span>
                </div>
                <span className="text-[9px] md:text-[10px] text-slate-600 font-bold uppercase">{new Date(task.dueDate).toLocaleDateString()}</span>
              </div>
            ))}
            {pendingTasks.length === 0 && (
               <p className="px-4 text-[10px] text-slate-600 font-black uppercase italic">Sem pendências críticas.</p>
            )}
          </div>
        </div>

        <div className="space-y-4 md:space-y-6">
           <div className="bg-[#111827]/60 p-5 md:p-6 rounded-[2rem] border border-white/5">
              <h4 className="text-[9px] md:text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                <Activity className="w-3.5 h-3.5 md:w-4 md:h-4" /> Diário
              </h4>
              {latestEntry ? (
                <div className="space-y-2">
                  <p className="text-xs md:text-sm text-slate-300 italic line-clamp-3 leading-relaxed">"{latestEntry.content}"</p>
                  <span className="inline-block px-2 py-0.5 bg-indigo-500/10 text-indigo-400 text-[8px] md:text-[9px] font-black rounded uppercase tracking-widest">{latestEntry.mood}</span>
                </div>
              ) : <p className="text-[10px] text-slate-600 italic font-black uppercase">Nenhum registro emocional.</p>}
           </div>
        </div>
      </div>
    </div>
  );
}

import { GoogleGenAI } from "@google/genai";
import { FinancialData } from "../types";

export const getFinancialAdvice = async (data: FinancialData, userQuery: string) => {
  // Inicialização correta conforme diretrizes: usar process.env.API_KEY diretamente
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contextSummary = {
    balance: data.transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0) - 
             data.transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0),
    pendingTasks: data.tasks.filter(t => !t.completed).length,
    latestMood: data.journal[0]?.mood || 'N/A',
    notesCount: data.notes.length,
    debtsCount: data.debts.filter(d => d.status !== 'paid').length,
    potes: data.potes.map(p => `${p.name}: R$ ${p.balance.toLocaleString('pt-BR')}`).join(', ')
  };

  const systemInstruction = `
    Você é o ZenOS Master Assistant, um sistema operacional pessoal e financeiro inteligente.
    Seu objetivo é ser o único ponto de contato para a vida produtiva, emocional e financeira do usuário.
    Analise os dados unificados e responda de forma executiva, clara e proativa.

    Estado Atual do Usuário:
    - Saldo Total: R$ ${contextSummary.balance}
    - Distribuição nos Potes: ${contextSummary.potes}
    - Dívidas Ativas: ${contextSummary.debtsCount}
    - Tarefas Pendentes: ${contextSummary.pendingTasks}
    - Último Estado Emocional: ${contextSummary.latestMood}

    Capacidades:
    1. Interpretar gastos e sugerir cortes baseados nos potes.
    2. Organizar tarefas e priorizar compromissos.
    3. Analisar tendências emocionais correlacionadas com gastos.

    Regras:
    - Use Markdown para formatação.
    - Seja empático, executivo e direto.
    - Responda SEMPRE em Português (Brasil).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Upgrade para o modelo Pro para raciocínio financeiro mais complexo
      contents: userQuery,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.7,
      },
    });

    return response.text;
  } catch (error) {
    console.error("ZenOS AI Error:", error);
    return "Desculpe, meu processamento neural falhou. Verifique sua conexão ou tente novamente em breve.";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, Receipt, Target, Wallet, BrainCircuit, Menu, X, Archive, 
  AlertCircle, CheckSquare, FileText, BookOpen, Calendar as CalendarIcon, Download,
  BarChart
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Task, Note, JournalEntry, CalendarEvent, Budget, FinancialGoal } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Tasks from './components/Tasks';
import Notes from './components/Notes';
import Journal from './components/Journal';
import Budgets from './components/Budgets';
import Goals from './components/Goals';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Investimento/Reserva', percentage: 20, balance: 0 },
];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);

  // Estados dos Módulos
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [tasks, setTasks] = useState<Task[]>(() => JSON.parse(localStorage.getItem('zen_tasks') || '[]'));
  const [notes, setNotes] = useState<Note[]>(() => JSON.parse(localStorage.getItem('zen_notes') || '[]'));
  const [journal, setJournal] = useState<JournalEntry[]>(() => JSON.parse(localStorage.getItem('zen_journal') || '[]'));
  const [events, setEvents] = useState<CalendarEvent[]>(() => JSON.parse(localStorage.getItem('zen_events') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  // Detectar Offline e Prompt de Instalação
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    const handleBeforeInstall = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    window.addEventListener('beforeinstallprompt', handleBeforeInstall);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.removeEventListener('beforeinstallprompt', handleBeforeInstall);
    };
  }, []);

  // Persistência
  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_tasks', JSON.stringify(tasks));
    localStorage.setItem('zen_notes', JSON.stringify(notes));
    localStorage.setItem('zen_journal', JSON.stringify(journal));
    localStorage.setItem('zen_events', JSON.stringify(events));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [transactions, potes, debts, tasks, notes, journal, events, budgets, goals]);

  const processedPotes = useMemo(() => {
    return potes.map(pote => {
      let balance = 0;
      transactions.forEach(t => {
        if (t.type === 'income') {
          balance += t.amount * (pote.percentage / 100);
        } else if (t.type === 'expense' && t.poteId === pote.id) {
          balance -= t.amount;
        }
      });
      return { ...pote, balance };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, tasks, notes, journal, events, budgets, goals
  }), [transactions, processedPotes, debts, tasks, notes, journal, events, budgets, goals]);

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string) => {
    // 1. Atualizar saldo da dívida
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    // 2. Registrar transação de despesa vinculada ao pote
    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    setTransactions(prev => [paymentTx, ...prev]);
  };

  const handleInstall = async () => {
    if (!deferredPrompt) return;
    try {
      deferredPrompt.prompt();
      const { outcome } = await deferredPrompt.userChoice;
      if (outcome === 'accepted') setDeferredPrompt(null);
    } catch (err) {
      console.warn('Installation prompt failed', err);
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard },
    { id: 'transactions', label: 'Finanças', icon: Receipt },
    { id: 'potes', label: 'Potes', icon: Archive },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle },
    { id: 'tasks', label: 'Tarefas', icon: CheckSquare },
    { id: 'notes', label: 'Notas', icon: FileText },
    { id: 'journal', label: 'Diário', icon: BookOpen },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100 font-sans overflow-hidden select-none">
      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-40 lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-50 transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-[#0a0c14] border-r border-white/5 flex flex-col
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-slate-500" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-4 mt-6 space-y-1 overflow-y-auto">
          {navItems.map((item) => (
            <button 
              key={item.id} 
              onClick={() => { setView(item.id as AppView); setIsSidebarOpen(false); }} 
              className={`
                w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                ${view === item.id ? 'bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 shadow-lg shadow-indigo-600/5' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800/40'}
              `}
            >
              <item.icon className="w-5 h-5 flex-shrink-0" />
              <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="p-4 space-y-2">
          {deferredPrompt && (
            <button 
              onClick={handleInstall}
              className="w-full flex items-center gap-3 px-4 py-3 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all"
            >
              <Download className="w-4 h-4" />
              <span className="lg:hidden xl:block">Instalar App</span>
            </button>
          )}

          {isOffline && (
            <div className="flex items-center gap-3 px-4 py-3 bg-rose-500/10 text-rose-400 border border-rose-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest">
              <div className="w-2 h-2 bg-rose-500 rounded-full animate-pulse" />
              <span className="lg:hidden xl:block">Modo Offline</span>
            </div>
          )}
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative">
        <header className="h-16 glass sticky top-0 z-30 px-4 md:px-8 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-900 rounded-xl text-indigo-400"><Menu /></button>
            <h1 className="text-sm md:text-xl font-black uppercase tracking-[0.2em] truncate">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="w-10 h-10 rounded-2xl bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
            <BrainCircuit className="w-5 h-5 text-indigo-400" />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 pb-24 lg:pb-12">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && (
            <Transactions 
              transactions={transactions} 
              potes={processedPotes} 
              onAdd={(t) => setTransactions([t, ...transactions])} 
              onDelete={(id) => setTransactions(transactions.filter(t => t.id !== id))}
              onEdit={(updated) => setTransactions(transactions.map(t => t.id === updated.id ? updated : t))}
            />
          )}
          {view === 'debts' && (
            <Debts 
              debts={debts} 
              potes={processedPotes} 
              onAdd={(d) => setDebts([...debts, d])} 
              onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} 
              onPay={handleDebtPayment} 
            />
          )}
          {view === 'tasks' && <Tasks tasks={tasks} onUpdate={setTasks} />}
          {view === 'notes' && <Notes notes={notes} onUpdate={setNotes} />}
          {view === 'journal' && <Journal journal={journal} onUpdate={setJournal} />}
          {view === 'potes' && (
            <Potes 
              potes={processedPotes} 
              onUpdate={(updatedPotes) => {
                // Salvar apenas metadados, o balance é calculado
                const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                setPotes(clean as Jar[]);
              }} 
            />
          )}
          {view === 'goals' && <Goals goals={goals} onAdd={(g) => setGoals([...goals, g])} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Debt, Jar } from '../types';
import { Plus, CheckCircle2, AlertTriangle, Calendar, CreditCard, ChevronRight, DollarSign, X } from 'lucide-react';

interface DebtsProps {
  debts: Debt[];
  potes: Jar[];
  onAdd: (d: Debt) => void;
  onUpdate: (d: Debt) => void;
  onPay: (d: Debt, amount: number, poteId: string) => void;
}

export default function Debts({ debts, potes, onAdd, onUpdate, onPay }: DebtsProps) {
  const [showAddModal, setShowAddModal] = useState(false);
  const [paymentModal, setPaymentModal] = useState<{ debt: Debt | null, amount: number, poteId: string }>({ 
    debt: null, 
    amount: 0, 
    poteId: '' 
  });

  const [newDebt, setNewDebt] = useState<Partial<Debt>>({
    name: '', totalAmount: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros'
  });

  const totalDebt = debts.filter(d => d.status !== 'paid').reduce((acc, d) => acc + d.remainingAmount, 0);

  const handleOpenPayment = (debt: Debt) => {
    setPaymentModal({
      debt,
      amount: debt.remainingAmount,
      poteId: potes.length > 0 ? potes[0].id : ''
    });
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDebt.name || !newDebt.totalAmount) return;
    onAdd({
      ...newDebt as Debt,
      id: Math.random().toString(36).substr(2, 9),
      remainingAmount: newDebt.totalAmount,
      status: 'active'
    });
    setShowAddModal(false);
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-rose-500/10 border border-rose-500/20 p-6 rounded-3xl">
          <span className="text-[10px] font-black text-rose-400 uppercase tracking-widest block mb-2">Total em Aberto</span>
          <p className="text-3xl font-black text-white tracking-tighter">R$ {totalDebt.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
        </div>
        <div className="bg-emerald-500/10 border border-emerald-500/20 p-6 rounded-3xl">
          <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest block mb-2">Dívidas Quitadas</span>
          <p className="text-3xl font-black text-white tracking-tighter">{debts.filter(d => d.status === 'paid').length}</p>
        </div>
        <div className="flex items-center justify-center">
            <button 
              onClick={() => setShowAddModal(true)}
              className="w-full h-full flex items-center justify-center gap-3 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/10"
            >
              <Plus className="w-5 h-5" /> Nova Dívida
            </button>
        </div>
      </div>

      <div className="space-y-4">
        <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] flex items-center gap-3">
          Compromissos Financeiros <div className="h-px flex-1 bg-slate-800"></div>
