                    <div className="bg-slate-900/40 p-3 rounded-2xl border border-white/5">
                        <span className="text-[9px] text-slate-500 font-black uppercase block mb-1">Restante</span>
                        <span className="text-sm font-bold text-rose-400">R$ {debt.remainingAmount.toLocaleString()}</span>
                    </div>
                </div>

                <div className="space-y-2 mb-6">
                  <div className="flex justify-between items-center text-[10px] font-black uppercase text-slate-500 tracking-widest">
                    <span>Progresso</span>
                    <span className="text-indigo-400">{progress.toFixed(0)}%</span>
                  </div>
                  <div className="h-2 bg-slate-800 rounded-full overflow-hidden">
