          <div className="bg-[#1e293b] rounded-3xl w-full max-w-sm p-8 border border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-white tracking-tight">Amortizar {paymentModal.debt.name}</h3>
              <button onClick={() => setPaymentModal({ debt: null, amount: 0, poteId: '' })}><X className="text-slate-500 hover:text-white" /></button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-2">Valor do Pagamento</label>
                <input 
                  type="number" 
                  className="w-full px-4 py-3 bg-slate-900/50 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.amount}
                  onChange={(e) => setPaymentModal({ ...paymentModal, amount: parseFloat(e.target.value) || 0 })}
                />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-2">Pote de Origem</label>
                <select 
                  className="w-full px-4 py-3 bg-slate-900/50 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.poteId}
                  onChange={(e) => setPaymentModal({ ...paymentModal, poteId: e.target.value })}
                >
                  <option value="">Selecione...</option>
                  {potes.map(p => <option key={p.id} value={p.id}>{p.name} (Saldo: R$ {p.balance.toLocaleString()})</option>)}
                </select>
              </div>
              <button 
                onClick={() => {
                  if (paymentModal.debt && paymentModal.amount > 0 && paymentModal.poteId) {
                    onPay(paymentModal.debt, paymentModal.amount, paymentModal.poteId);
                    setPaymentModal({ debt: null, amount: 0, poteId: '' });
                  } else {
                    alert("Preencha todos os campos corretamente.");
                  }
                }}
                className="w-full py-4 bg-emerald-500 text-emerald-950 font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-emerald-400 transition-all shadow-xl"
              >
                Confirmar Pagamento
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Nova Dívida */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
           <div className="bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-white uppercase tracking-tighter">Registrar Dívida</h3>
              <button onClick={() => setShowAddModal(false)}><X className="text-slate-600" /></button>
            </div>
            <form onSubmit={handleAddSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Descrição</label>
                <input required className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.name} onChange={e => setNewDebt({...newDebt, name: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Valor Total R$</label>
                <input type="number" step="0.01" required className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.totalAmount || ''} onChange={e => setNewDebt({...newDebt, totalAmount: parseFloat(e.target.value)})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Vencimento</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.dueDate} onChange={e => setNewDebt({...newDebt, dueDate: e.target.value})} />
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">Salvar Compromisso</button>
            </form>
           </div>
        </div>
      )}
    </div>
  );
}

