import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, Receipt, Target, Wallet, BrainCircuit, Menu, X, Archive, 
  AlertCircle, CheckSquare, FileText, BookOpen, Calendar as CalendarIcon, Download,
  BarChart3
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Task, Note, JournalEntry, CalendarEvent, Budget, FinancialGoal } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Tasks from './components/Tasks';
import Notes from './components/Notes';
import Journal from './components/Journal';
import Budgets from './components/Budgets';
import Goals from './components/Goals';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Investimento/Reserva', percentage: 20, balance: 0 },
];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);

  // Estados dos Módulos
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [tasks, setTasks] = useState<Task[]>(() => JSON.parse(localStorage.getItem('zen_tasks') || '[]'));
  const [notes, setNotes] = useState<Note[]>(() => JSON.parse(localStorage.getItem('zen_notes') || '[]'));
  const [journal, setJournal] = useState<JournalEntry[]>(() => JSON.parse(localStorage.getItem('zen_journal') || '[]'));
  const [events, setEvents] = useState<CalendarEvent[]>(() => JSON.parse(localStorage.getItem('zen_events') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    const handleBeforeInstall = (e: any) => { e.preventDefault(); setDeferredPrompt(e); };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    window.addEventListener('beforeinstallprompt', handleBeforeInstall);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.removeEventListener('beforeinstallprompt', handleBeforeInstall);
    };
  }, []);

  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_tasks', JSON.stringify(tasks));
    localStorage.setItem('zen_notes', JSON.stringify(notes));
    localStorage.setItem('zen_journal', JSON.stringify(journal));
    localStorage.setItem('zen_events', JSON.stringify(events));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [transactions, potes, debts, tasks, notes, journal, events, budgets, goals]);

  const processedPotes = useMemo(() => {
    return potes.map(pote => {
      let balance = 0;
      transactions.forEach(t => {
        if (t.type === 'income') {
          balance += t.amount * (pote.percentage / 100);
        } else if (t.type === 'expense' && t.poteId === pote.id) {
          balance -= t.amount;
        }
      });
      return { ...pote, balance };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, tasks, notes, journal, events, budgets, goals
  }), [transactions, processedPotes, debts, tasks, notes, journal, events, budgets, goals]);

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    setTransactions(prev => [paymentTx, ...prev]);
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard },
    { id: 'transactions', label: 'Finanças', icon: Receipt },
    { id: 'potes', label: 'Potes', icon: Archive },
    { id: 'budgets', label: 'Orçamentos', icon: BarChart3 },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle },
    { id: 'tasks', label: 'Tarefas', icon: CheckSquare },
    { id: 'notes', label: 'Notas', icon: FileText },
    { id: 'journal', label: 'Diário', icon: BookOpen },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100 font-sans overflow-hidden select-none">
      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-40 lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-50 transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-[#0a0c14] border-r border-white/5 flex flex-col
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-slate-500" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-4 mt-6 space-y-1 overflow-y-auto">
          {navItems.map((item) => (
            <button 
              key={item.id} 
              onClick={() => { setView(item.id as AppView); setIsSidebarOpen(false); }} 
              className={`
                w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                ${view === item.id ? 'bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 shadow-lg shadow-indigo-600/5' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800/40'}
              `}
            >
              <item.icon className="w-5 h-5 flex-shrink-0" />
              <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
            </button>
          ))}
        </nav>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative">
        <header className="h-16 glass sticky top-0 z-30 px-4 md:px-8 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-900 rounded-xl text-indigo-400"><Menu /></button>
            <h1 className="text-sm md:text-xl font-black uppercase tracking-[0.2em] truncate">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="w-10 h-10 rounded-2xl bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
            <BrainCircuit className="w-5 h-5 text-indigo-400" />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 pb-24 lg:pb-12">
          {view === 'dashboard' && <Dashboard data={financialData} />}
          {view === 'transactions' && (
            <Transactions 
              transactions={transactions} 
              potes={processedPotes} 
              onAdd={(t) => setTransactions([t, ...transactions])} 
              onDelete={(id) => setTransactions(transactions.filter(t => t.id !== id))}
              onEdit={(updated) => setTransactions(transactions.map(t => t.id === updated.id ? updated : t))}
            />
          )}
          {view === 'debts' && (
            <Debts debts={debts} potes={processedPotes} onAdd={(d) => setDebts([...debts, d])} onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} onPay={handleDebtPayment} />
          )}
          {view === 'tasks' && <Tasks tasks={tasks} onUpdate={setTasks} />}
          {view === 'notes' && <Notes notes={notes} onUpdate={setNotes} />}
          {view === 'journal' && <Journal journal={journal} onUpdate={setJournal} />}
          {view === 'potes' && (
            <Potes 
              potes={processedPotes} 
              onUpdate={(updatedPotes) => {
                const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                setPotes(clean as Jar[]);
              }} 
            />
          )}
          {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} onUpdate={setBudgets} />}
          {view === 'goals' && <Goals goals={goals} onAdd={(g) => setGoals([...goals, g])} onUpdate={setGoals} />}
          {view === 'advisor' && <AIAdvisor data={financialData} />}
        </div>
      </main>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Budget, Transaction } from '../types';
import { AlertCircle, Plus, X, BarChart3, TrendingDown } from 'lucide-react';

interface BudgetsProps {
  budgets: Budget[];
  transactions: Transaction[];
  onUpdate: (b: Budget[]) => void;
}

export default function Budgets({ budgets, transactions, onUpdate }: BudgetsProps) {
  const [isAdding, setIsAdding] = useState(false);
  const [newBudget, setNewBudget] = useState({ category: '', limit: 0 });

  const categorySpending = useMemo(() => {
    const map: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.type === 'expense') {
        map[t.category] = (map[t.category] || 0) + t.amount;
      }
    });
    return map;
  }, [transactions]);

  const processedBudgets = useMemo(() => {
    return budgets.map(b => ({
      ...b,
      spent: categorySpending[b.category] || 0
    }));
  }, [budgets, categorySpending]);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newBudget.category || newBudget.limit <= 0) return;
    const budget: Budget = {
      id: Math.random().toString(36).substr(2, 9),
      category: newBudget.category,
      limit: newBudget.limit,
      spent: 0
    };
    onUpdate([...budgets, budget]);
    setNewBudget({ category: '', limit: 0 });
    setIsAdding(false);
  };

  const updateLimit = (id: string, newLimit: number) => {
    onUpdate(budgets.map(b => b.id === id ? { ...b, limit: newLimit } : b));
  };

  const removeBudget = (id: string) => {
    onUpdate(budgets.filter(b => b.id !== id));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-black text-white uppercase tracking-tighter">Limites de Consumo</h2>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Acompanhe seus orçamentos mensais</p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
        >
          <Plus className="w-4 h-4" /> Novo Orçamento
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {processedBudgets.map((budget) => {
          const percentage = (budget.spent / budget.limit) * 100;
          const isOver = percentage > 100;
          const isNear = percentage > 85 && !isOver;

          return (
            <div key={budget.id} className="bg-[#0a0c14] p-6 rounded-[2rem] border border-white/5 shadow-xl flex flex-col group relative">
              <button 
                onClick={() => removeBudget(budget.id)}
                className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 p-2 text-slate-700 hover:text-rose-500 transition-all"
              >
                <X className="w-4 h-4" />
              </button>

              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-xl ${isOver ? 'bg-rose-500/10 text-rose-400' : 'bg-indigo-500/10 text-indigo-400'}`}>
                    <BarChart3 className="w-4 h-4" />
                  </div>
                  <h3 className="font-bold text-slate-200 text-sm uppercase tracking-wider">{budget.category}</h3>
                </div>
                {isOver && <AlertCircle className="w-5 h-5 text-rose-500 animate-pulse" />}
              </div>

              <div className="flex justify-between text-[10px] font-black uppercase tracking-widest mb-2">
                <span className="text-slate-500">Gasto: R$ {budget.spent.toLocaleString()}</span>
                <span className="text-slate-200">Limite: R$ {budget.limit.toLocaleString()}</span>
              </div>

              <div className="w-full bg-slate-900 h-2 rounded-full overflow-hidden mb-4">
                <div 
                  className={`h-full transition-all duration-700 ${isOver ? 'bg-rose-500' : isNear ? 'bg-amber-500' : 'bg-indigo-500'}`}
                  style={{ width: `${Math.min(percentage, 100)}%` }}
                />
              </div>

              <div className="mt-auto pt-4 flex justify-between items-center border-t border-white/5">
                <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg ${isOver ? 'bg-rose-500/10 text-rose-500' : isNear ? 'bg-amber-500/10 text-amber-500' : 'bg-emerald-500/10 text-emerald-500'}`}>
                  {isOver ? 'Limite Excedido' : `${(100 - percentage).toFixed(0)}% restante`}
                </span>
                <button 
                  onClick={() => updateLimit(budget.id, budget.limit + 500)}
                  className="text-indigo-400 text-[9px] font-black uppercase tracking-widest hover:text-indigo-300 transition-colors"
                >
                  + R$ 500
                </button>
              </div>
            </div>
          );
        })}
        {processedBudgets.length === 0 && (
          <div className="md:col-span-2 lg:col-span-3 text-center py-20 bg-slate-900/20 rounded-3xl border border-dashed border-white/10">
            <p className="text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Nenhum limite definido</p>
          </div>
        )}
      </div>

      {isAdding && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-white uppercase tracking-tighter">Novo Limite</h3>
              <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-white/5 rounded-full"><X className="w-6 h-6 text-slate-500" /></button>
            </div>
            <form onSubmit={handleAdd} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Categoria</label>
                <input required className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newBudget.category} onChange={e => setNewBudget({...newBudget, category: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Limite Mensal R$</label>
                <input type="number" required className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newBudget.limit || ''} onChange={e => setNewBudget({...newBudget, limit: parseFloat(e.target.value)})} />
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">Confirmar</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { FinancialGoal } from '../types';
import { Target, Trophy, Calendar, Plus, X, ArrowUpRight } from 'lucide-react';

interface GoalsProps {
  goals: FinancialGoal[];
  onAdd: (g: FinancialGoal) => void;
  onUpdate: (goals: FinancialGoal[]) => void;
}

export default function Goals({ goals, onAdd, onUpdate }: GoalsProps) {
  const [showAdd, setShowAdd] = useState(false);
  const [newGoal, setNewGoal] = useState({ name: '', targetAmount: 0, deadline: '' });

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newGoal.name || newGoal.targetAmount <= 0) return;
    const goal: FinancialGoal = {
      id: Math.random().toString(36).substr(2, 9),
      name: newGoal.name,
      targetAmount: newGoal.targetAmount,
      currentAmount: 0,
      deadline: newGoal.deadline || new Date().toISOString().split('T')[0]
    };
    onAdd(goal);
    setNewGoal({ name: '', targetAmount: 0, deadline: '' });
    setShowAdd(false);
  };

  const depositToGoal = (id: string, amount: number) => {
    onUpdate(goals.map(g => g.id === id ? { ...g, currentAmount: g.currentAmount + amount } : g));
  };

  const removeGoal = (id: string) => {
    onUpdate(goals.filter(g => g.id !== id));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-black text-white uppercase tracking-tighter">Grandes Sonhos</h2>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Acompanhe sua evolução financeira</p>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
        >
          <Plus className="w-4 h-4" /> Criar Meta
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {goals.map((goal) => {
          const progress = (goal.currentAmount / goal.targetAmount) * 100;
          const remaining = goal.targetAmount - goal.currentAmount;

          return (
            <div key={goal.id} className="bg-[#0a0c14] p-8 rounded-[2.5rem] border border-white/5 shadow-xl flex gap-6 group relative">
              <button 
                onClick={() => removeGoal(goal.id)}
                className="absolute top-6 right-6 opacity-0 group-hover:opacity-100 p-2 text-slate-700 hover:text-rose-500 transition-all"
              >
                <X className="w-5 h-5" />
              </button>

              <div className="hidden sm:flex flex-col items-center justify-center bg-indigo-600/10 w-24 rounded-[1.5rem] p-4 border border-indigo-600/20">
                <Trophy className="w-8 h-8 text-indigo-400 mb-2" />
                <span className="text-[10px] font-black text-indigo-400">{progress.toFixed(0)}%</span>
              </div>

              <div className="flex-1 space-y-4">
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="text-xl font-black text-white tracking-tight">{goal.name}</h3>
                    <div className="flex items-center gap-2 text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-1">
                      <Calendar className="w-3 h-3 text-indigo-400" />
                      {new Date(goal.deadline).toLocaleDateString('pt-BR')}
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[9px] text-slate-500 font-black uppercase">Faltam</p>
                    <p className="font-black text-rose-400 text-lg">R$ {remaining.toLocaleString()}</p>
                  </div>
                </div>

                <div className="space-y-2">
                  <div className="w-full bg-slate-900 h-3 rounded-full overflow-hidden">
                    <div 
                      className="bg-indigo-600 h-full transition-all duration-1000 ease-out"
                      style={{ width: `${Math.min(progress, 100)}%` }}
                    />
                  </div>
                  <div className="flex justify-between text-[10px] font-black uppercase tracking-widest">
                    <span className="text-slate-500">R$ {goal.currentAmount.toLocaleString()} acumulado</span>
                    <span className="text-slate-200">Alvo: R$ {goal.targetAmount.toLocaleString()}</span>
                  </div>
                </div>

                <div className="flex gap-2 pt-2">
                  <button 
                    onClick={() => depositToGoal(goal.id, 100)}
                    className="flex-1 py-3 bg-white/5 text-slate-200 border border-white/10 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-600 hover:text-white transition-all flex items-center justify-center gap-2"
                  >
                    <ArrowUpRight className="w-4 h-4" /> Aportar R$ 100
                  </button>
                </div>
              </div>
            </div>
          );
        })}
        {goals.length === 0 && (
          <div className="lg:col-span-2 text-center py-20 bg-slate-900/20 rounded-3xl border border-dashed border-white/10">
            <p className="text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Nenhuma meta ativa</p>
          </div>
        )}
      </div>

      {showAdd && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-white uppercase tracking-tighter">Novo Sonho</h3>
              <button onClick={() => setShowAdd(false)} className="p-2 hover:bg-white/5 rounded-full"><X className="w-6 h-6 text-slate-500" /></button>
            </div>
            <form onSubmit={handleAdd} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Descrição do Sonho</label>
                <input required className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newGoal.name} onChange={e => setNewGoal({...newGoal, name: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Meta Financeira R$</label>
                <input type="number" required className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newGoal.targetAmount || ''} onChange={e => setNewGoal({...newGoal, targetAmount: parseFloat(e.target.value)})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Prazo Estimado</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newGoal.deadline} onChange={e => setNewGoal({...newGoal, deadline: e.target.value})} />
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">Ativar Sonho</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
